const guideLessons = [
    { id: 1, slug: "guide-what-is-claude", level: 1, title: "Что такое Claude на самом деле", summary: "Не поисковик и не калькулятор — большая языковая модель, с которой можно разговаривать. По мотивам Module 1 официального курса Anthropic Academy «Claude 101».", order_in_level: 1, doc_url: "https://anthropic.skilljar.com/claude-101", related_entry: "con-cyrillic-tokenization", related_tools: [], related_prompts: [], body_md: "![](/guide/1/guide-what-is-claude-hero.png)\n\n### ❓ Что это\nClaude — большая языковая модель (LLM) от Anthropic. Ты пишешь ей текстом (или голосом, или файлом), она отвечает текстом — пишет код, объясняет, редактирует, ищет ошибки, придумывает, планирует. Внутри — нейросеть, обученная на огромном количестве текста, которая предсказывает, какой ответ будет наиболее уместным для твоего запроса, а не ищет готовый ответ в базе данных.\n\nПользоваться можно тремя способами, и это не три разных продукта, а три поверхности одной и той же модели: **сайт/приложение claude.ai** (обычный чат), **Cowork** (Claude работает в фоне над более длинными задачами, в том числе с доступом к твоим файлам и инструментам) и **Claude Code** (терминал для разработчиков). Подробно про все три — в отдельном уроке дальше в этом уровне; здесь сосредоточимся на обычном чате — он же входная точка для остальных.\n\nВажно понимать разницу с поисковиком с самого начала: поисковик находит существующие страницы по ключевым словам, Claude — **генерирует** ответ заново под конкретно твой вопрос, опираясь на то, чему научился при обучении, плюс на то, что ты рассказал ему в этом диалоге. Он не «гуглит» за тебя (если только явно не включён режим Research — про него на уровне 2), а рассуждает над твоим запросом и держит контекст всего разговора, а не отвечает на каждое сообщение изолированно.\n\n### 🎯 Зачем тебе\nЭто собеседник, который не устаёт от повторяющихся вопросов, доступен 24/7 и не считает вопрос «слишком простым» или «слишком странным». Чем точнее объяснишь, что нужно, тем полезнее ответ — этому конкретно посвящён один из следующих уроков.\n\nПрактическая польза с первого дня: можно сразу проверить, как модель справляется именно с твоими задачами — переводом, объяснением незнакомого термина, составлением плана, черновиком письма, разбором кода. Не нужно ничего настраивать заранее ради первого полезного результата.\n\n### 💻 Как это выглядит на практике\nРегистрация на **claude.ai** — через email или Google-аккаунт, без карты для бесплатного плана. После входа видишь чистое поле ввода — это и есть весь интерфейс на старте, никаких сложных меню:\n\nПечатаешь вопрос, жмёшь Enter (или кнопку отправки на телефоне) — ответ начинает печататься сразу, по частям, а не одним куском (это называется **streaming** — модель «пишет» ответ на глазах, как человек, а не выгружает готовый текст целиком через несколько секунд молчания).\n\nСправа/снизу от поля ввода — селектор модели (на скриншоте выше — «Opus 4.5»): можно переключаться между несколькими моделями Claude прямо в диалоге. Что это за модели и когда какую включать — отдельный урок дальше в этом же уровне.\n\nДальше у тебя есть выбор: продолжить в этом же диалоге («уточни пункт 2» или «а если по-другому») или начать новый — если тема совсем не связана с предыдущей. Разные диалоги **не видят контекст друг друга** (если только не включена память — см. урок про Memory на уровне 2), так что для несвязанных тем новый чат — правильный выбор, чтобы не путать модель посторонним контекстом.\n\nНа бесплатном плане есть дневной лимит сообщений — для знакомства и повседневных задач обычно достаточно. Платные планы (Pro и выше) снимают ограничение и открывают более мощные модели.\n\n### 🔗 Смотри в приложении\nЕсли интересно, как устроены модели Claude технически изнутри — глубокий разбор в статье [«Токенизация кириллицы: почему русский язык стоит дороже»](entry:con-cyrillic-tokenization). Сравнение моделей Sonnet/Opus/Haiku и когда какую включать — в следующем уроке этого уровня и в статье [«Матрица моделей»](entry:api-models-matrix).\n\n### ⚠️ Частая ошибка новичка\nПисать одну фразу без контекста и ждать идеального результата с первого раза — как гуглить. Claude работает лучше как диалог: задал вопрос, посмотрел на ответ, уточнил, что не так. Это нормально и быстрее, чем пытаться сформулировать идеальный запрос сразу — даже опытные пользователи почти никогда не получают финальный результат с первой попытки на нетривиальных задачах.\n\nВторая частая ошибка — воспринимать первый ответ как единственно возможный и сдаваться, если он не подошёл. Модель не «обидится» на «нет, не то, попробуй иначе» — переспрашивать можно сколько угодно раз в рамках одного диалога, это не расходует отдельный лимит за каждую попытку.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», Module 1 «Meet Claude» — anthropic.skilljar.com/claude-101; support.claude.com" },
  { id: 2, slug: "guide-first-conversation", level: 1, title: "Твой первый разговор с Claude", summary: "Как задать первый вопрос так, чтобы получить реальный толк, а не общие слова.", order_in_level: 2, doc_url: "https://anthropic.skilljar.com/claude-101", related_entry: null, related_tools: [], related_prompts: [], body_md: "### ❓ Что это\n«Первый разговор» — это не один идеальный вопрос, а обмен репликами, как с человеком. Ты пишешь запрос — Claude отвечает — ты смотришь на ответ и решаешь, что делать дальше: принять как есть, попросить переделать, уточнить деталь, задать смежный вопрос. Разница между «плохим» и «хорошим» первым диалогом почти никогда не в магических словах — она в том, сколько реального контекста задачи попало в текст, а не осталось только у тебя в голове.\n\nПростой пример: «напиши текст про отпуск» и «напиши пост в Telegram-канал про отпуск в Грузии для аудитории 25-35 лет, тон — лёгкий, с самоиронией, 3-4 абзаца, без канцелярита» — формально один и тот же топик, но второй запрос почти гарантированно не потребует переделки, а первый — почти гарантированно потребует.\n\n### 🎯 Зачем тебе\nПервое сообщение задаёт рамку всему диалогу: если сразу описать роль («ты — редактор технического блога»), формат ответа («списком, не более 5 пунктов») и ограничения («без жаргона»), Claude будет держать это на протяжении всего разговора, а не только в первом ответе. Экономит 2-3 раунда переспрашиваний на каждой задаче — это быстро окупается, если общаешься с Claude регулярно.\n\n### 💻 Как это выглядит на практике\nХорошая стартовая структура сообщения — не жёсткий шаблон, а три вопроса самому себе перед отправкой:\n1. **Что именно нужно на выходе?** — текст/код/план/объяснение, и в каком виде (список, таблица, диалог, код с комментариями).\n2. **Для кого или для чего это?** — аудитория, контекст использования, тон.\n3. **Какие есть ограничения?** — длина, что нельзя использовать, что уже пробовал и не сработало.\n\nНе обязательно отвечать на все три в первом сообщении — но чем больше из этого явно проговорено, тем меньше кругов уточнений. Дальше диалог работает итеративно: получил ответ → указал, что поправить («сделай короче», «убери третий пункт», «а теперь то же самое, но для другой аудитории») → получил уточнённую версию. Это нормальный рабочий цикл, а не признак того, что «промпт был плохим».\n\nОтдельно стоит помнить про **длину контекста одного диалога**: Claude помнит всё, что было сказано в этом чате, но не помнит соседние чаты (если не включена память — см. уровень 2). Если разговор ушёл далеко от темы или стал очень длинным, иногда быстрее начать новый диалог и коротко пересказать суть, чем тащить за собой весь груз предыдущих 40 сообщений.\n\n### 🔗 Смотри в приложении\nЕсли задача — направить Claude в процессе диалога, а не просто написать хороший первый промпт, пригодится готовый промпт [«Сузить фокус на конкретную часть задачи»](prompt:steer-narrow-scope) — рабочий приём для случаев, когда модель начинает решать больше, чем просили.\n\n### ⚠️ Частая ошибка новичка\nФормулировать запрос как задание для поисковика («Грузия отпуск лучшие места») вместо обращения к собеседнику («посоветуй 3 города в Грузии для недельной поездки в сентябре, не туристические места, интересны для человека, который любит вино и архитектуру»). Оба формата technically «работают», но второй экономит один-два раунда уточнений почти всегда.\n\nВторая ошибка — пытаться уместить сложную многосоставную задачу в одно длинное предложение без структуры. Если задача состоит из нескольких частей, разбить их списком или отдельными пунктами — Claude лучше следует явной структуре, чем распутывает её из сплошного текста.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», урок «Your first conversation with Claude» — anthropic.skilljar.com/claude-101" },
  { id: 3, slug: "guide-better-results", level: 1, title: "Как получать более качественные ответы", summary: "Уточнения, контекст, итерации — рабочие приёмы, а не «магические слова» для промпта.", order_in_level: 3, doc_url: "https://anthropic.skilljar.com/claude-101", related_entry: "con-context-window-limits", related_tools: [], related_prompts: [], body_md: "### ❓ Что это\nКачество ответа Claude почти всегда зависит от количества и точности контекста, а не от «правильных ключевых слов» или специального синтаксиса. Модель не читает мысли — она работает с тем, что реально написано в диалоге: текущим сообщением, всей историей чата, и, если это включено, содержимым проекта или памятью (уровень 2). Улучшение результата — это в первую очередь управление контекстом, а не подбор заклинаний.\n\nТри рабочих рычага, которые реально двигают качество ответа: **явные примеры** («вот похожий текст, который мне нравится по стилю»), **явные ограничения** («не длиннее 100 слов», «без канцелярита», «только на Python 3.12») и **явная роль/аудитория** («объясни как для человека без технического бэкграунда»).\n\n### 🎯 Зачем тебе\nНа практике разница в качестве ответа между «просто спросил» и «спросил с примером и ограничениями» — это разница между результатом, который нужно полностью переписывать, и результатом, который нужно чуть подправить. Особенно заметно на задачах с субъективным критерием качества — стиль текста, тон письма, структура кода под конвенции конкретного проекта.\n\n### 💻 Как это выглядит на практике\nРаботает простой цикл «спросил → посмотрел → уточнил», и в нём есть несколько практических приёмов:\n\n**Дай пример вместо описания.** Вместо «напиши в дружелюбном тоне» — приложи 2-3 предложения, которые уже звучат так, как нужно, и попроси: «пиши в таком же тоне». Модели гораздо проще скопировать паттерн из примера, чем угадать, что значит «дружелюбный» именно для тебя.\n\n**Проси показать промежуточный результат на длинных задачах.** Если задача многошаговая (например, «проанализируй файл и предложи 5 правок»), не жди сразу финал — попроси сначала показать план или список того, что будет сделано. Это экономит время, если Claude пошёл не в ту сторону — переделать план дешевле, чем переделывать готовый результат.\n\n**Спроси «почему», прежде чем сказать «переделай».** Если ответ не совпал с ожиданием, но не очевидно плохой — иногда полезнее спросить, почему модель выбрала именно такой подход, чем сразу просить другой. Может выясниться, что у выбора была причина, которую ты не учёл (например, более новый способ решения задачи, о котором ты не знал).\n\n**Не бойся сказать «нет, не то» напрямую.** Максимально конкретная обратная связь («убери второй абзац, он повторяет первый» вместо общего «переделай») почти всегда быстрее доводит до нужного результата, чем расплывчатая критика.\n\n### 🔗 Смотри в приложении\nДва готовых промпта из раздела Промпты закрывают эти сценарии один в один: [«Остановиться и показать промежуточный результат»](prompt:steer-checkpoint-before-continuing) — для длинных задач, и [«Спросить логику решения перед тем как менять его»](prompt:steer-explain-then-redirect) — когда ответ выглядит подозрительно, но не факт, что неправильно. Если хочешь понять, почему длинные диалоги иногда «теряют мысль» и как это связано с качеством ответов — читай [«Контекстное окно и эффект затухания внимания»](entry:con-context-window-limits).\n\n### ⚠️ Частая ошибка новичка\nСчитать, что более длинный и «умный»-звучащий промпт автоматически даёт лучший результат. На практике конкретика важнее объёма: короткий запрос с точным примером почти всегда обходит длинный запрос из общих формулировок без единого конкретного ограничения или образца.\n\nВторая ошибка — молча смиряться с неидеальным первым ответом вместо того, чтобы конкретно указать, что не так. Абстрактное «попробуй ещё раз» почти не улучшает результат — модели, как и человеку, нужна конкретная точка, за что зацепиться.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», урок «Getting better results» — anthropic.skilljar.com/claude-101" },
  { id: 4, slug: "guide-claude-surfaces", level: 1, title: "Chat, Cowork, Code — три способа работать с Claude", summary: "Одна и та же модель, три разных режима работы — обычный диалог, фоновый помощник и терминал для разработки.", order_in_level: 4, doc_url: "https://anthropic.skilljar.com/claude-101", related_entry: null, related_tools: [], related_prompts: [], body_md: "### ❓ Что это\nClaude — это не один интерфейс, а одна модель, доступная через три разных режима работы, каждый для своей задачи:\n\n- **Chat** — обычный диалог на claude.ai или в приложении, из предыдущих уроков. Ты пишешь — Claude отвечает сразу же, в реальном времени. Лучше всего подходит для разовых вопросов, коротких задач, творческой и аналитической работы «в моменте».\n- **Cowork** — Claude работает более самостоятельно и дольше, в фоне, с доступом к твоим файлам и инструментам (по разрешению), не требуя, чтобы ты сидел и ждал каждый ответ. Подходит для задач, которые занимают несколько минут или дольше и состоят из многих шагов — не разовый вопрос, а полноценное поручение.\n- **Claude Code** — версия для разработчиков, живёт в терминале (или в IDE как расширение). Читает код целого проекта, редактирует файлы, запускает команды, работает с git — подробно про это на уровне 3, здесь только ориентир, что такой режим существует.\n\n### 🎯 Зачем тебе\nВыбор режима — это не вопрос «какой лучше», а вопрос «что за задача перед тобой». Разовый вопрос или короткая правка текста — Chat. Задача, которую не хочется контролировать шаг за шагом («разбери эти 50 файлов и собери сводку», «проверь эти документы на несоответствия») — Cowork. Работа с кодовой базой напрямую — Claude Code. Знание, что варианта три, а не один, экономит время — не приходится пытаться выполнить в обычном чате то, для чего лучше подходит Cowork.\n\n### 💻 Как это выглядит на практике\n**Cowork** настраивается через глобальные инструкции — то, что должно быть верно для всех задач Cowork сразу (например, «всегда отвечай на русском» или «перед изменением файлов показывай план»):\n\n![](/guide/1/guide-claude-surfaces-cowork.png)\n\nТакие инструкции экономят время на каждой новой задаче в Cowork — не нужно повторять одни и те же указания заново.\n\n**Claude Code** выглядит совсем иначе — это терминал, где Claude видит структуру проекта и может сам предлагать и вносить правки в код:\n\n![](/guide/1/guide-claude-surfaces-code.gif)\n\nНа скриншоте — реальный запрос («audit and improve test coverage», то есть «проверь и улучши покрытие тестами») в работающей сессии Claude Code: видно текущую модель, путь к проекту и историю диалога прямо в терминале. Устанавливается отдельно (`curl -fsSL https://claude.ai/install.sh | bash` на macOS/Linux) — подробный разбор установки и первых команд будет на уровне 3, когда дойдём до инженерной части.\n\nОдно и то же **знание модели** переносится между всеми тремя режимами — если объяснил Claude контекст задачи в Chat, это не «останется» автоматически в Cowork или Code (это разные сессии), но сам навык формулировать запрос работает одинаково везде.\n\n### 🔗 Смотри в приложении\nПолная карточка инструмента с историей установки, реальными командами и типичными граблями — в разделе Софт: [Claude Code — официальный CLI-агент](tool:anthropics/claude-code).\n\n### ⚠️ Частая ошибка новичка\nПытаться выполнить в обычном Chat задачу, для которой на самом деле нужен Cowork или Claude Code — например, «пройдись по 30 файлам в моей папке и всё поправь». Обычный чат не имеет доступа к файлам на диске сам по себе (только к тому, что ты явно загрузил в диалог) — для работы с реальными файлами и длинными автономными задачами нужен именно Cowork или Claude Code, не Chat.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», урок «Claude desktop app: Chat, Cowork, Code» — anthropic.skilljar.com/claude-101" },
  { id: 5, slug: "guide-which-model", level: 1, title: "Модели: какую выбрать (Sonnet/Opus/Haiku/Fable простыми словами)", summary: "Разные модели Claude — чем отличаются и когда какую включать в обычном диалоге.", order_in_level: 5, doc_url: "https://platform.claude.com/docs/en/about-claude/models/choosing-a-model", related_entry: "con-model-selection", related_tools: [], related_prompts: [], body_md: "![](/guide/1/guide-what-is-claude-hero.png)\n\n### ❓ Что это\nУ Claude несколько моделей — как разные «режимы мощности» одного и того же собеседника. На практике в диалоге чаще всего встречаются **Sonnet**, **Opus** и **Haiku**, а для самых требовательных задач — **Fable**. Разница — в том, насколько глубоко модель «думает» перед ответом и сколько это стоит по времени и деньгам (для платных планов и API — по деньгам напрямую, для бесплатного плана — косвенно, через дневной лимит сообщений).\n\nВажно: это не «слабая» и «сильная» версия одного и того же интеллекта в духе «Haiku глупее». Правильнее думать об этом как о разных инструментах для разных задач — молоток не хуже отвёртки, они просто для разного. На скриншоте выше как раз виден переключатель модели прямо над полем ввода — в примере выбран Opus 4.5.\n\n### 🎯 Зачем тебе\nНе всегда нужна самая мощная модель — иногда важнее скорость и цена. Если выбрать не тот режим, можно либо переплатить временем/лимитом за простую задачу, либо не дождаться нужного качества на сложной. Разница в скорости ответа между Haiku и Opus может быть в разы — это ощутимо, если пользуешься Claude весь день на потоке мелких задач.\n\n### 💻 Как это выглядит на практике\nПрактическое правило по умолчанию:\n\n- **Haiku** — для быстрых, простых, массовых задач: короткий ответ на прямой вопрос, классификация текста («это жалоба или похвала?»), простое форматирование, извлечение данных в структурированный вид. Отвечает почти мгновенно.\n- **Sonnet** — универсальный выбор по умолчанию для большинства повседневных задач: код, тексты, анализ, объяснения. С неё стоит начинать почти всегда, если явно не знаешь, что задача очень простая или очень сложная.\n- **Opus** — для по-настоящему сложных многошаговых задач, где важна глубина рассуждения больше скорости: сложная архитектура кода, стратегический план с множеством взаимосвязанных условий, разбор запутанной юридической или финансовой ситуации.\n- **Fable** — самая мощная модель, для длинных автономных агентных сценариев и задач на пределе возможностей текущего поколения моделей; для обычного повседневного диалога избыточна почти всегда.\n\nВ интерфейсе claude.ai модель выбирается в выпадающем списке над полем ввода — переключить её можно в любой момент, даже посреди диалога, если чувствуешь, что текущая модель не справляется или, наоборот, задача оказалась проще, чем казалось.\n\n### 🔗 Смотри в приложении\nПодробная методология выбора модели под задачу (не только «на глаз», а по конкретным критериям) — в статье [«Методология выбора модели под задачу»](entry:con-model-selection). Полная сравнительная таблица характеристик и цен — в статье [«Матрица моделей»](entry:api-models-matrix), а если считаешь стоимость запросов в токенах — пригодится калькулятор токенов на Home.\n\n### ⚠️ Частая ошибка новичка\nВсегда включать самую мощную модель «на всякий случай» — не всегда быстрее и не всегда лучше для простых запросов, только медленнее и дороже (или быстрее съедает дневной лимит на бесплатном плане). Начинай с Sonnet как с базового выбора и переключайся на Opus/Fable, только если реально упёрся в качество ответа на сложной задаче.\n\nОбратная ошибка тоже встречается: пытаться решить действительно сложную многошаговую задачу на Haiku ради скорости и разочаровываться в качестве ответа — хотя проблема не в модели вообще, а в неверном выборе конкретной модели под конкретную задачу.\n\n### 🔗 Официальный источник\nplatform.claude.com/docs/en/about-claude/models/choosing-a-model" },
  { id: 6, slug: "guide-uploading-files", level: 1, title: "Загрузка файлов и изображений — что Клод умеет читать", summary: "Какие форматы можно закинуть в чат и что Claude реально с ними сделает.", order_in_level: 6, doc_url: "https://support.claude.com/en/articles/8241126-upload-files-to-claude", related_entry: "api-vision-processing", related_tools: [], related_prompts: [], body_md: "![](/guide/1/guide-what-is-claude-hero.png)\n\n### ❓ Что это\nВ поле ввода есть кнопка-скрепка — через неё можно прикрепить файл прямо к сообщению: PDF, изображение (скриншот, фото), текстовый документ, таблицу, код. Claude «видит» содержимое файла так же, как если бы ты вставил текст в чат — включая текст на картинках (распознаёт скриншоты, сканы, фото документов), таблицы и графики.\n\nМожно прикрепить сразу несколько файлов к одному сообщению, если задача требует сравнить их между собой или собрать информацию из разных источников.\n\n### 🎯 Зачем тебе\nНе нужно вручную перепечатывать текст из PDF или описывать словами, что на скриншоте — можно просто прикрепить файл и спросить напрямую: «что не так в этой таблице», «перепиши этот договор проще», «что за ошибка на этом скриншоте». Это экономит реально много времени на рутине, особенно если работаешь с документами регулярно.\n\nВторая важная польза — точность. Пересказ содержимого файла своими словами всегда теряет детали или искажает их; прямая загрузка файла даёт модели работать с оригиналом, без твоей интерпретации по пути.\n\n### 💻 Как это выглядит на практике\nПрикрепи скриншот с текстом ошибки из терминала и напиши «объясни, что тут сломалось» — Claude прочитает текст с картинки и ответит по существу, без необходимости перепечатывать код ошибки руками. Аналогично работает с фото документов, графиками, рукописными заметками.\n\n![](/guide/1/guide-uploading-files-detail.svg)\n\nНесколько практических сценариев, которые реально экономят время:\n- **Договор или счёт в PDF** — «найди в этом договоре пункты про штрафы» вместо чтения десяти страниц юридического текста самому.\n- **Фото рукописных заметок** — Claude распознаёт почерк (если он разборчивый) и превращает его в аккуратный печатный текст.\n- **Скриншот графика или дашборда** — «что здесь необычного» — модель может заметить аномалию, которую взгляд пропускает при беглом просмотре.\n- **Таблица Excel/CSV** — вставленная напрямую или прикреплённая файлом, можно попросить посчитать, отсортировать, найти закономерность.\n\nДля очень больших документов (сотни страниц) стоит помнить, что у контекстного окна есть предел — если файл не помещается целиком, лучше загружать частями или явно указывать, какой раздел важен.\n\n### 🔗 Смотри в приложении\nКак именно Claude «видит» изображения технически (какие форматы, ограничения по размеру, точность распознавания) — в статье [«Vision API: обработка изображений»](entry:api-vision-processing).\n\n### ⚠️ Частая ошибка новичка\nЗагружать файл и не объяснять, что с ним сделать — просто «вот файл» без вопроса. Модели нужно явное задание: что именно найти, объяснить или переписать, даже если файл сам по себе всё «объясняет» на первый взгляд. Без явного вопроса Claude, скорее всего, даст общее описание содержимого — не то, что тебе реально было нужно.\n\nВторая ошибка — загружать конфиденциальные данные (пароли, номера карт, личные документы третьих лиц) без необходимости. Файлы обрабатываются согласно политике конфиденциальности Anthropic, но хорошая привычка — не прикреплять то, что не обязательно для решения задачи.\n\n### 🔗 Официальный источник\nsupport.claude.com" },
  { id: 200, slug: "guide-projects", level: 2, title: "Проекты — отдельный контекст для каждой задачи", summary: "Изолированные рабочие пространства с файлами и своими инструкциями, чтобы не путать разные задачи между собой. По мотивам Module 2 курса Anthropic Academy «Claude 101».", order_in_level: 1, doc_url: "https://support.claude.com/en/articles/9519177-how-can-i-create-and-manage-projects", related_entry: "ca-projects-knowledge", related_tools: [], related_prompts: [], body_md: "![](/guide/2/guide-projects-hero.png)\n\n### ❓ Что это\n**Проекты** — отдельные рабочие пространства в claude.ai (на платных планах), каждое со своим набором загруженных файлов (**Project Knowledge**) и своими инструкциями, которые применяются ко всем диалогам внутри проекта. По сути это способ дать модели постоянную «папку с материалами по теме», а не прикреплять одни и те же файлы заново в каждом чате.\n\nВнутри проекта можно вести сколько угодно отдельных диалогов — они все опираются на одну и ту же базу знаний и инструкции, но обсуждают разные подзадачи, не путаясь друг с другом. Существующий чат можно в любой момент переместить в проект — на скриншоте выше как раз модальное окно «Move chat», которое предлагает выбрать, в какой проект переложить разговор.\n\n### 🎯 Зачем тебе\nЕсли ведёшь несколько задач параллельно — обычный чат превращается в кашу, и приходится каждый раз заново объяснять контекст. Проект жёстко разделяет: в одном лежат файлы и правила для одной задачи, в другом — для совсем другой, они не смешиваются, и Claude не путает термины или контекст из одного проекта с другим.\n\nЭто особенно полезно, если работаешь с командой над общей темой: инструкции проекта задают единый стиль ответов для всех, кто им пользуется, а не для каждого лично — не нужно каждому участнику объяснять одно и то же с нуля.\n\n### 💻 Как это выглядит на практике\nСоздание проекта — одна кнопка на главной странице claude.ai. Дальше два ключевых раздела внутри:\n- **Project Knowledge** (справа) — сюда загружаются файлы: документация, примеры кода, договоры, брендбук. Всё, что здесь лежит, автоматически доступно в любом чате внутри проекта — не нужно прикреплять заново.\n- **Инструкции проекта** — текстовое поле, которое задаёт правила для всех диалогов сразу: тон ответов, формат, что учитывать всегда («отвечай только на русском», «все примеры кода — на TypeScript»).\n\nПроекты можно закреплять («звёздочка» в меню — отмечать важные, чтобы не искать среди остальных), перемещать в них существующие чаты (см. скриншот выше) и архивировать, когда работа закончена, не удаляя историю совсем.\n\n### 🔗 Смотри в приложении\nБолее глубокий разбор Project Knowledge и лимитов на размер базы знаний — в статье [«Проекты и Project Knowledge»](entry:ca-projects-knowledge).\n\n### ⚠️ Частая ошибка новичка\nЗаводить один проект «на всё» вместо отдельных проектов под разные темы — теряется весь смысл изоляции контекста, и Claude снова начинает путать материалы разных задач между собой, как в обычном чате без проектов.\n\nВторая ошибка — загружать в Project Knowledge вообще всё подряд «на всякий случай». У базы знаний проекта есть предел объёма — вместо релевантных материалов Claude начинает получать шум из документов, которые к текущей подзадаче не относятся, что снижает точность ответов.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», Module 2 «Organizing your work and knowledge» — anthropic.skilljar.com/claude-101; support.claude.com" },
  { id: 201, slug: "guide-artifacts-intro", level: 2, title: "Artifacts — что это и зачем", summary: "Отдельное окно сбоку, где можно сразу посмотреть на код, документ или интерактивную страницу, а не читать текст. По мотивам Module 2 курса Anthropic Academy «Claude 101».", order_in_level: 2, doc_url: "https://support.claude.com/en/articles/9487310-what-are-artifacts-and-how-do-i-use-them", related_entry: "ca-artifacts-deep-dive", related_tools: [], related_prompts: [], body_md: "### ❓ Что это\nЕсли попросить Claude написать что-то крупное и самостоятельное — код страницы, диаграмму, документ — ответ открывается не прямо в чате, а в отдельном окне сбоку. Это и есть **Artifact**. У него две вкладки: **Code** (сам код или текст) и **Preview** (как это выглядит вживую, если применимо — например, готовая веб-страница, диаграмма Mermaid или интерактивный React-компонент).\n\nArtifact не разовый — он живёт как отдельный объект рядом с диалогом. Видна история версий, можно вернуться к предыдущему варианту и продолжать работать с ним, пока сам диалог идёт своим чередом.\n\n### 🎯 Зачем тебе\nНе нужно копировать код себе на компьютер и запускать его, чтобы увидеть результат — можно сразу кликать по кнопкам прямо в Preview, крутить диаграмму, проверять, как страница выглядит на разных размерах экрана. Артефакт также живёт отдельно от диалога — можно попросить поправить что-то конкретное («сделай кнопку крупнее», «поменяй цвет фона на тёмный»), и он обновится, не потеряв остального кода.\n\nЭто особенно ценно для нетехнических пользователей: не нужно знать, что такое HTML или React, чтобы получить и увидеть результат — Claude сам пишет код, а Preview сразу показывает, что получилось, без единого дополнительного шага с твоей стороны.\n\n### 💻 Как это выглядит на практике\nЗапрос вроде «Сделай интерактивный калькулятор чаевых на HTML» почти гарантированно откроет Artifact с рабочей страницей во вкладке Preview — можно сразу вводить сумму и смотреть результат, не выходя из браузера.\n\nДругие типичные сценарии, где Claude сам решает открыть Artifact:\n- **Диаграммы и схемы** — попросил нарисовать flowchart процесса, получил Mermaid-диаграмму, которую можно скопировать в документацию.\n- **Документы** — большой текст (договор, статья, план проекта) открывается отдельно, чтобы не растягивать диалог на экран и было удобно скопировать целиком.\n- **Мини-приложения** — небольшие интерактивные инструменты (конвертер валют, генератор паролей, простая игра) сразу работают во вкладке Preview.\n\nЕсли нужно забрать результат — есть кнопка скачивания файла или копирования кода прямо из вкладки Code, без необходимости выделять текст вручную.\n\n### 🔗 Смотри в приложении\nПолный разбор форматов артефактов, версионирования и ограничений песочницы — в статье [«Артефакты: интерактивная среда в браузере»](entry:ca-artifacts-deep-dive).\n\n### ⚠️ Частая ошибка новичка\nЖдать, что в Artifact заработает вообще всё, включая обращения к внешним серверам или тяжёлые библиотеки — Artifacts выполняются в изолированной песочнице без доступа к интернету. Подходят для фронтенда, визуализаций и самостоятельных скриптов, не для бэкенд-логики с базами данных, реальными платежами или запросами к внешним API.\n\nВторая ошибка — не замечать, что Artifact вообще открылся, и искать результат в основном окне чата. Если сбоку не появилось окно, а ответ выглядит как обычный текст с кодом внутри — значит, Claude счёл задачу недостаточно самостоятельной для отдельного артефакта; можно прямо попросить «оформи это как Artifact».\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», Module 2 «Organizing your work and knowledge» — anthropic.skilljar.com/claude-101; support.claude.com" },
  { id: 202, slug: "guide-skills", level: 2, title: "Skills — навыки, которые Claude подключает по задаче", summary: "Готовые «инструкции + шаблоны» для повторяющихся задач — от офисных документов до задач по бренд-гайдам.", order_in_level: 3, doc_url: "https://support.claude.com/en/articles/12512176-what-are-skills", related_entry: "cc-skills-vs-plugins", related_tools: [], related_prompts: [], body_md: "![](/guide/2/guide-skills-hero.png)\n\n### ❓ Что это\n**Skills** — папки с инструкциями, скриптами и шаблонами, которые Claude подключает динамически под конкретную задачу. Skill не меняет саму модель — он даёт ей процедурное знание: как именно выполнить конкретный тип работы повторяемым способом (например, создать презентацию по фирменному стилю компании или заполнить Excel-отчёт по шаблону).\n\nУ Anthropic есть готовые Skills для типовых офисных задач (PowerPoint, Excel, Word, PDF) — они уже включены в claude.ai, не нужно ничего доустанавливать. Можно и создавать свои собственные, если у тебя есть повторяющаяся задача со своим форматом.\n\n### 🎯 Зачем тебе\nБез Skill каждый раз приходится заново объяснять Claude в промпте, как именно должен выглядеть результат — какой формат, какие разделы, какой стиль оформления. Skill один раз фиксирует эти правила, и дальше просто включается по названию задачи — не нужно пересказывать инструкцию с нуля в каждом диалоге.\n\nЭто особенно полезно для команд: если у компании есть свой формат отчёта или брендбук, Skill с этими правилами можно один раз настроить и переиспользовать — результат будет единообразным независимо от того, кто из команды просит Claude выполнить задачу.\n\n### 💻 Как это выглядит на практике\nЧтобы посмотреть доступные Skills — в настройках аккаунта раздел «Customize» → «Skills», кнопка «+» → «Browse skills» открывает каталог. На скриншоте выше — меню управления уже подключённым Skill: можно попробовать его в чате («Try in chat»), скачать, отредактировать через Claude или удалить, если больше не нужен.\n\nИспользование в диалоге не требует специального синтаксиса — Claude сам определяет, что задача подходит под конкретный Skill, и подключает нужные инструкции автоматически. Например, попросив «сделай презентацию по этим тезисам в фирменном стиле», при подключённом Skill для PowerPoint получаешь готовый файл нужного формата, а не просто текстовый план слайдов.\n\nРазница между Skills и MCP-коннекторами (о них — следующий урок): MCP даёт Claude доступ к внешним инструментам и сервисам, а Skills учат Claude, как именно этими инструментами эффективно пользоваться. Это дополняющие, а не конкурирующие механизмы.\n\n### 🔗 Смотри в приложении\nЧем Skills отличаются от плагинов и других способов расширения Claude Code — в статье [«Skills и плагины: чем расширяется Claude Code»](entry:cc-skills-vs-plugins). Официальный репозиторий с примерами и спецификацией Skills — в разделе Софт: [Anthropic Skills — официальные скиллы](tool:anthropics/skills).\n\n### ⚠️ Частая ошибка новичка\nПытаться вручную «включить» Skill командой или упоминанием в промпте, как если бы это был режим или флаг — Skills подключаются автоматически по смыслу задачи, а не по явному запросу пользователя. Если Skill не подключился — стоит переформулировать задачу ближе к тому, для чего Skill предназначен, а не искать способ вызвать его напрямую.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», Module 2 «Organizing your work and knowledge» — anthropic.skilljar.com/claude-101; support.claude.com" },
  { id: 203, slug: "guide-connectors", level: 2, title: "Коннекторы — подключи Notion, Google Drive и другие сервисы", summary: "Живая синхронизация с внешними источниками вместо ручной перезагрузки файлов после каждой правки.", order_in_level: 4, doc_url: "https://support.claude.com/en/articles/11176164-use-connectors-to-extend-claude-s-capabilities", related_entry: "ca-data-connectors", related_tools: [], related_prompts: [], body_md: "![](/guide/2/guide-connectors.svg)\n\n### ❓ Что это\n**Connectors** — интеграции, которые связывают claude.ai с внешними хранилищами вроде Notion или Google Drive напрямую, без ручной загрузки файлов каждый раз, когда что-то меняется. В отличие от файла, один раз загруженного в Project Knowledge, коннектор читает актуальную версию источника в момент запроса.\n\nКоннекторы настраиваются один раз на уровне Проекта или аккаунта и дальше работают в фоне — не нужно ничего повторно синхронизировать вручную.\n\n### 🎯 Зачем тебе\nЕсли документация команды живёт в Notion, коннектор избавляет от постоянного пересохранения и повторной загрузки — Claude видит актуальную версию документа сразу, без твоего участия. Это устраняет классическую проблему устаревшего контекста: файл, загруженный неделю назад, мог с тех пор поменяться десять раз, а коннектор всегда смотрит на живую версию.\n\nОсобенно ценно в командной работе — если документация постоянно обновляется разными людьми, вручную отслеживать актуальность вложений просто нереально.\n\n### 💻 Как это выглядит на практике\nВ настройках Проекта: «Подключить источник данных» → выбираешь сервис (например, Google Drive) → авторизуешься через свой аккаунт → указываешь конкретную папку или страницу. Дальше при ответе Claude сам подтягивает свежий текст оттуда, если вопрос это подразумевает.\n\n![](/guide/2/guide-connectors-detail.svg)\n\nТипичные сценарии использования:\n- **Notion как база знаний команды** — «что у нас написано про процесс онбординга новых сотрудников» подтягивает актуальную страницу, а не устаревшую копию.\n- **Google Drive с рабочими документами** — можно спросить про содержимое конкретной таблицы или презентации, не скачивая и не прикрепляя файл вручную.\n- **Комбинация нескольких коннекторов** — например, сверить, что написано в Notion, с тем, что в таблице Google Sheets, в одном запросе.\n\nСписок поддерживаемых сервисов расширяется со временем — стоит периодически проверять раздел настроек, если нужного тебе сервиса раньше не было.\n\n### 🔗 Смотри в приложении\nПолный список поддерживаемых сервисов и разбор, чем коннектор отличается от разового прикрепления файла — в статье [«Коннекторы данных: Notion, Google Drive и другие»](entry:ca-data-connectors).\n\n### ⚠️ Частая ошибка новичка\nПодключать доступ ко всему диску целиком «на всякий случай». Давай доступ только к конкретным папкам или страницам, которые реально нужны в задаче — особенно если работаешь в командном пространстве, где доступ видят другие участники, а излишне широкий доступ создаёт ненужный риск утечки чувствительной информации.\n\nВторая ошибка — забыть, что коннектор подключён, и не понимать, откуда модель взяла тот или иной факт в ответе. Если ответ содержит неожиданную информацию, стоит проверить список подключённых источников — возможно, дело не в «выдумке» модели, а в реальном документе, который она честно процитировала.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», Module 3 «Expanding Claude's reach» — anthropic.skilljar.com/claude-101; support.claude.com" },
  { id: 204, slug: "guide-research-mode", level: 2, title: "Режим Research — глубокий многошаговый поиск", summary: "Когда обычного быстрого ответа недостаточно и нужен настоящий разбор темы с источниками.", order_in_level: 5, doc_url: "https://support.claude.com/en/articles/11088861-use-research-on-claude", related_entry: "ca-research-mode", related_tools: [], related_prompts: [], body_md: "![](/guide/2/guide-research-mode.svg)\n\n### ❓ Что это\n**Research** — режим, в котором Claude не просто отвечает с ходу, а итеративно ищет информацию: делает несколько запросов, уточняет их по мере находок, сопоставляет источники между собой и в конце собирает связный отчёт со ссылками. Это принципиально другой процесс, чем обычный ответ модели по памяти — здесь Claude активно обращается к актуальным данным из интернета, а не только опирается на знания, полученные при обучении.\n\nРежим включается отдельно от обычного чата — обычно через переключатель или выбор режима рядом с полем ввода, в зависимости от текущей версии интерфейса.\n\n### 🎯 Зачем тебе\nПолезно, когда готового ответа не найти на первой странице поисковика — например, сравнить условия в разных странах, разобраться, что изменилось в инструменте за последний год, или собрать обзор мнений по спорному вопросу из нескольких независимых источников сразу. Обычный чат отвечает по знаниям на момент обучения модели и не гарантированно свежий; Research специально устроен так, чтобы находить актуальную информацию именно сейчас.\n\nЭто экономит часы ручного гугления и открытия десятка вкладок — Research делает всю черновую работу поиска и сопоставления сам, а тебе остаётся проверить итоговые выводы и источники.\n\n### 💻 Как это выглядит на практике\nВключаешь режим Research и задаёшь вопрос вроде «разберись, что изменилось в API X за последний год» — вместо одного ответа Claude проходит цепочку: поиск → уточняющий поиск на основе того, что нашёл → сверка источников между собой на предмет противоречий → итоговый связный текст со ссылками на конкретные материалы.\n\n![](/guide/2/guide-research-mode-detail.svg)\n\nХорошие кандидаты для режима Research:\n- **Сравнительный анализ** — «сравни условия ипотеки в трёх банках» требует найти и сопоставить данные из разных источников.\n- **Отслеживание изменений** — «что нового появилось в этой библиотеке за последние полгода» требует поиска по датам и версиям.\n- **Проверка утверждения** — «правда ли, что...» с опорой на реальные источники, а не общие рассуждения.\n\nФинальный отчёт обычно содержит явные ссылки на источники — стоит проверять хотя бы ключевые из них самостоятельно, особенно если решение на основе ответа имеет реальные последствия (финансовые, юридические, медицинские).\n\n### 🔗 Смотри в приложении\nПодробнее о том, как Research сочетается с подключёнными источниками (Gmail, Google Drive) — в статье [«Режим исследования (Research)»](entry:ca-research-mode).\n\n### ⚠️ Частая ошибка новичка\nВключать Research для простых вопросов, на которые и так есть быстрый прямой ответ («сколько будет 15% от 200» не требует поиска в интернете). Это медленный режим — ответ может занимать несколько минут вместо секунд и тратит лимит быстрее обычного чата, включай его осознанно для реально комплексных задач, требующих актуальных данных из нескольких источников.\n\nВторая ошибка — слепо доверять итоговому отчёту без проверки, особенно на важных решениях. Research снижает объём ручной работы, но не отменяет здравый смысл: источники всё равно стоит бегло просматривать самому, если цена ошибки высока.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude 101», Module 3 «Expanding Claude's reach» — anthropic.skilljar.com/claude-101; support.claude.com" },
  { id: 205, slug: "guide-memory", level: 2, title: "Memory — Claude помнит тебя между чатами", summary: "Как Claude запоминает предпочтения и детали проектов, чтобы не объяснять всё заново в каждом новом диалоге.", order_in_level: 6, doc_url: "https://support.claude.com", related_entry: "ca-user-memory-web", related_tools: [], related_prompts: [], body_md: "![](/guide/2/guide-memory.svg)\n\n### ❓ Что это\n**Memory** — сквозная персонализация в claude.ai: модель сама замечает и запоминает важные факты о тебе (стек технологий, текущие проекты, предпочтения по стилю общения) и переносит их в новые, не связанные между собой диалоги. В отличие от Проектов, память не привязана к конкретной теме — она про тебя в целом, как пользователя.\n\nПамять формируется постепенно и незаметно: не нужно ничего специально «сохранять» — модель сама решает, какие факты стоит запомнить, основываясь на том, что регулярно всплывает в твоих диалогах.\n\n### 🎯 Зачем тебе\nБез памяти каждый новый чат — это чистый лист: приходится заново объяснять, кто ты и над чем работаешь, даже если ты писал ровно то же самое вчера в другом диалоге. С включённой памятью не нужно повторять один и тот же онбординг в десятый раз — Claude уже знает контекст, который ты давал раньше.\n\nЭто особенно ощутимо, если ты пользуешься Claude регулярно для похожих задач — со временем ответы становятся точнее именно под твою ситуацию, без дополнительных усилий с твоей стороны.\n\n### 💻 Как это выглядит на практике\nУпомянул в одном чате, что пишешь на Python и работаешь над телеграм-ботом — эта информация появится в Settings → Personalization → Memory и будет автоматически использоваться в следующих диалогах, даже если ты о ней не напоминал. Например, попросив «напиши функцию для парсинга дат» в новом чате, скорее всего получишь код сразу на Python, без уточняющего вопроса «на каком языке?».\n\n![](/guide/2/guide-memory-detail.svg)\n\nЧто обычно попадает в память естественным путём:\n- **Технический контекст** — язык программирования, фреймворки, инструменты, которыми ты регулярно пользуешься.\n- **Текущие проекты** — над чем ты сейчас работаешь, если это упоминалось не единожды.\n- **Предпочтения по формату** — например, если ты часто просишь «короче» или «без вступлений», это может закрепиться как общая манера ответов.\n\nВсю память можно посмотреть, отредактировать вручную или полностью очистить в разделе настроек — она не скрыта от тебя, ты полностью контролируешь, что там хранится.\n\n### 🔗 Смотри в приложении\nПодробнее о том, как устроена персонализация и что именно попадает в память — в статье [«Долгосрочная память (Memory) в Claude.ai»](entry:ca-user-memory-web).\n\n### ⚠️ Частая ошибка новичка\nНе заглядывать в память месяцами — она может забиться устаревшими фактами о проекте, который ты уже закрыл, или о технологиях, которые больше не используешь. Периодически заходи в настройки и вручную удаляй то, что больше не актуально, иначе устаревший контекст может незаметно влиять на новые ответы не в ту сторону.\n\nВторая ошибка — полагаться на память там, где нужна стопроцентная точность. Память — это удобство, а не гарантия: для критичных деталей (точные цифры, специфические требования конкретной задачи) всё равно стоит явно указать их в промпте, а не надеяться, что модель «и так помнит».\n\n### 🔗 Официальный источник\nsupport.claude.com" },
  { id: 206, slug: "guide-styles", level: 2, title: "Styles — настрой тон ответов один раз", summary: "Сохраняемые пресеты поведения модели, чтобы не дописывать «отвечай короче» в конце каждого сообщения.", order_in_level: 7, doc_url: "https://support.claude.com", related_entry: "ca-custom-styles", related_tools: [], related_prompts: [], body_md: "![](/guide/2/guide-styles.svg)\n\n### ❓ Что это\n**Styles** — сохраняемые пресеты тона и формата ответа. По сути, обёртка над системным промптом, которую можно включить один раз в настройках и дальше просто общаться, не повторяя одни и те же указания в каждом сообщении. Стиль применяется глобально ко всем твоим диалогам (в отличие от инструкций Проекта, которые действуют только внутри конкретного Проекта).\n\nПо умолчанию доступно несколько готовых стилей от Anthropic, плюс возможность создать неограниченное количество своих и переключаться между ними в один клик.\n\n### 🎯 Зачем тебе\nПо умолчанию Claude склонен отвечать развёрнуто и вежливо, с пояснениями и оговорками — это хорошо для обучающих задач, но избыточно, если тебе нужен быстрый рабочий ответ. Если нужен сухой технический справочник или, наоборот, разговорный неформальный тон — настроенный один раз стиль экономит время на каждом отдельном ответе, а не только на промптах.\n\nСтили полезны и для единообразия: если ты пишешь много однотипного контента (посты, ответы клиентам, код-ревью), один стиль гарантирует одинаковый тон каждый раз, вместо того чтобы каждый раз заново формулировать пожелания и получать чуть разный результат.\n\n### 💻 Как это выглядит на практике\nВ настройках claude.ai есть раздел Styles с готовыми пресетами (например, «Concise» — короткие ответы без вводных фраз, «Formal» — деловой тон) и возможностью создать свой: «Отвечай сразу по сути, без вступлений, структурируй списками, не используй восклицательные знаки». Выбранный стиль применяется ко всем новым сообщениям, пока ты его не сменишь на другой.\n\n![](/guide/2/guide-styles-detail.svg)\n\nПримеры полезных кастомных стилей и когда они пригождаются:\n- **«Строгий редактор»** — для проверки текстов: без похвал, только конкретные замечания и что исправить.\n- **«Объясни как для новичка»** — для обучения новой теме: без жаргона, с аналогиями из повседневной жизни.\n- **«Быстрый черновик»** — для мозгового штурма: короткие варианты без долгих объяснений, чтобы быстро перебрать идеи.\n\nСтиль можно переключать посреди работы, если задача внутри одного диалога сменилась — например, сначала «мозговой штурм» для идей, потом «строгий редактор» для их проверки.\n\n### 🔗 Смотри в приложении\nКак создать свой Style и примеры готовых конфигураций — в статье [«Styles: кастомизация тональности ответов»](entry:ca-custom-styles).\n\n### ⚠️ Частая ошибка новичка\nВключить стиль и забыть про него — если внутри конкретного Проекта есть свои инструкции, а стиль им противоречит (например, стиль просит краткость, а инструкции проекта требуют подробных пояснений), ответ получится смешанным и не совсем таким, как ожидаешь. Проверяй, не спорят ли стиль и инструкции проекта друг с другом, если результат кажется странным.\n\nВторая ошибка — создавать слишком общий стиль вида «отвечай хорошо» без конкретики. Как и с промптами, чем конкретнее сформулирован стиль (что именно короче, что именно избегать, какая структура нужна), тем предсказуемее результат.\n\n### 🔗 Официальный источник\nsupport.claude.com" },
  { id: 300, slug: "guide-claude-code-intro", level: 3, title: "Claude Code — что это и как работает", summary: "Агент, который живёт в командной строке, понимает структуру проекта и сам правит код. По мотивам Module 1 курса Anthropic Academy «Claude Code 101».", order_in_level: 1, doc_url: "https://anthropic.skilljar.com/claude-code-101", related_entry: null, related_tools: [], related_prompts: [], body_md: "![](/guide/1/guide-claude-surfaces-code.gif)\n\n### ❓ Что это\n**Claude Code** — официальный агентный CLI-инструмент от Anthropic. В отличие от claude.ai, он работает прямо в терминале, видит файлы твоего проекта, может сам их читать, менять, запускать команды и коммитить в git. Это уже не просто «чат, который пишет код» — это агент, который выполняет реальные действия в твоей файловой системе, шаг за шагом, пока не решит задачу.\n\nКлючевое отличие от обычного чата: Claude Code не просто советует, что сделать, а делает это сам — читает файл, находит нужное место, правит, запускает тесты, проверяет результат, и если что-то не сработало — пробует иначе, без твоего постоянного участия в каждом шаге.\n\n### 🎯 Зачем тебе\nЕсли ты пишешь код, Claude Code избавляет от постоянного копирования кусков туда-сюда между чатом в браузере и редактором. Ты просто говоришь ему, что сделать — он сам находит нужные файлы, правит их и показывает диф (наглядное сравнение «было / стало») для проверки перед тем, как изменения окончательно применятся.\n\nЭто меняет сам процесс работы: вместо «спроси — скопируй ответ — вставь в редактор — проверь — вернись спросить, что не так» получаешь «сформулируй задачу — Claude Code сам сделал — ты проверил диф — одобрил или попросил поправить». Особенно заметная экономия времени на рутинных, но объёмных задачах — массовый рефакторинг, добавление тестов, обновление зависимостей по всему проекту.\n\n### 💻 Как это выглядит на практике\nНа гифке выше — реальная сессия Claude Code: видно название модели (Sonnet 4.5), путь к проекту и текущий запрос («audit and improve test coverage») прямо в терминале — точно так же выглядит любая твоя сессия.\n\nТипичный рабочий цикл:\n1. Формулируешь задачу текстом: «добавь валидацию email в форму регистрации».\n2. Claude Code сам находит релевантные файлы — сканирует структуру проекта, а не спрашивает тебя, где что лежит.\n3. Вносит правки и показывает диф — что именно изменилось, файл за файлом.\n4. Ты проверяешь и одобряешь (или просишь переделать конкретную часть) — при первом использовании подтверждения запрашиваются на каждое действие, подробнее об этом на уроке про Permissions дальше в этом уровне.\n5. При необходимости Claude Code сам запускает тесты или линтер, чтобы убедиться, что ничего не сломалось.\n\nClaude Code также умеет работать с git напрямую — создавать коммиты с осмысленными сообщениями, смотреть историю изменений, разбираться в конфликтах при слиянии веток (подробнее — урок про рабочий процесс дальше в этом уровне).\n\n### 🔗 Смотри в приложении\nУстановка, реальные команды и типичные грабли — в карточке инструмента в разделе Софт: [Claude Code — официальный CLI-агент](tool:anthropics/claude-code).\n\n### ⚠️ Частая ошибка новичка\nДавать агенту слишком общую задачу без структуры проекта («сделай сайт лучше») — Claude Code работает намного точнее, если у него есть конкретика: какой файл, что именно поменять, какой результат ожидается. Расплывчатая задача заставляет агента гадать о твоих намерениях, и результат может оказаться совсем не тем, что ты имел в виду.\n\nВторая частая ошибка — не проверять диф перед принятием изменений, особенно на больших правках. Даже хороший агент иногда делает больше, чем просили, или интерпретирует задачу неожиданным образом — быстрый просмотр изменений перед подтверждением экономит время на исправлении ошибок позже.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 1 «What is Claude Code?» — anthropic.skilljar.com/claude-code-101; code.claude.com/docs" },
  { id: 301, slug: "guide-claude-code-first-prompt", level: 3, title: "Установка и твой первый запрос в Claude Code", summary: "От пустого терминала до первой реальной правки в проекте.", order_in_level: 2, doc_url: "https://anthropic.skilljar.com/claude-code-101", related_entry: "cc-slash-commands", related_tools: [], related_prompts: [], body_md: "### ❓ Что это\nУстановка Claude Code — одна команда в терминале, без отдельного лицензионного ключа сверх обычной подписки Claude:\n```bash\ncurl -fsSL https://claude.ai/install.sh | bash\n```\n(на Windows — аналогичный `irm https://claude.ai/install.ps1 | iex` через PowerShell). После установки команда `claude`, запущенная внутри папки проекта, открывает интерактивную сессию — Claude Code сразу видит структуру файлов в текущей директории, ничего дополнительно указывать не нужно.\n\n### 🎯 Зачем тебе\nПервый запрос задаёт тон всей работе с инструментом: если сформулировать задачу конкретно, с первого раза получаешь рабочий результат и доверие к инструменту растёт; если сформулировать расплывчато — первое впечатление будет «он не понимает, что мне нужно», хотя дело в формулировке, а не в возможностях агента.\n\n### 💻 Как это выглядит на практике\nЗаходишь в папку проекта и запускаешь сессию:\n```bash\ncd /путь/к/проекту\nclaude\n```\nДальше просто пишешь задачу текстом, как в обычном чате — но результат совсем другой: Claude Code читает реальные файлы проекта и предлагает конкретные правки, а не абстрактный совет.\n\nХороший первый запрос для знакомства с инструментом — что-то маленькое и проверяемое: «покажи структуру этого проекта и объясни, за что отвечает каждая папка» или «найди все TODO-комментарии в коде и покажи список». Такие задачи безопасны (ничего не меняют) и сразу показывают, как Claude Code исследует кодовую базу.\n\nПервая правка обычно выглядит так:\n1. Пишешь: «добавь docstring этой функции» (указав файл или вставив код).\n2. Claude Code находит функцию, предлагает диф — что именно добавится.\n3. Проверяешь и подтверждаешь (на первый запуск подтверждение запрашивается почти на каждое действие — это нормально, подробнее на уроке про Permissions).\n\nПолезно с самого начала знать про **слэш-команды** — служебные команды с префиксом `/` (например `/clear` для очистки контекста сессии, `/help` для списка возможностей) — это не то же самое, что обычный текстовый запрос к модели.\n\n### 🔗 Смотри в приложении\nПолный справочник встроенных слэш-команд — в статье [«Справочник по slash-командам»](entry:cc-slash-commands).\n\n### ⚠️ Частая ошибка новичка\nНачинать знакомство сразу с крупной задачи на боевом проекте («перепиши всю авторизацию») вместо маленькой безопасной («покажи, как устроена авторизация сейчас»). Первые запросы стоит выбирать так, чтобы легко было проверить результат и понять логику работы инструмента, прежде чем доверять ему более рискованные изменения.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 2 «Your First Prompt» — anthropic.skilljar.com/claude-code-101" },
  { id: 302, slug: "guide-claude-code-workflow", level: 3, title: "Рабочий процесс: Explore → Plan → Code → Commit", summary: "Проверенный порядок работы с Claude Code на нетривиальных задачах, плюс как управлять контекстом сессии.", order_in_level: 3, doc_url: "https://anthropic.skilljar.com/claude-code-101", related_entry: "cc-architecture-loops", related_tools: [], related_prompts: [], body_md: "### ❓ Что это\n**Explore → Plan → Code → Commit** — рекомендованный Anthropic порядок работы с Claude Code на задачах сложнее пары строк: сначала агент исследует кодовую базу (Explore), затем предлагает план изменений (Plan), только потом пишет код (Code), и в конце фиксирует результат коммитом (Commit). Это не единственный способ работать с инструментом, но самый предсказуемый на нетривиальных задачах.\n\nОтдельно от порядка шагов стоит **управление контекстом** — сессия Claude Code накапливает историю (прочитанные файлы, выполненные команды), и по мере роста задачи эта история может раздуваться, занимая всё больше «места» и постепенно снижая фокус на актуальной части работы.\n\n### 🎯 Зачем тебе\nПропуск фазы Plan — самая частая причина, когда агент делает не то, что имелось в виду: без явного плана он может начать писать код по своей интерпретации задачи, а расхождение с твоими ожиданиями обнаружится только на этапе готового результата, когда переделка обходится дороже. Явный план перед кодом — это возможность поймать недопонимание на дешёвом этапе, а не после того, как правки уже внесены.\n\nУправление контекстом напрямую влияет на качество ответов в длинных сессиях: чем длиннее история, тем больше в ней шума из уже неактуальных деталей, что может размывать фокус модели на текущей подзадаче — та же механика, что описана в статье про контекстное окно.\n\n### 💻 Как это выглядит на практике\nНа практике цикл выглядит так:\n1. **Explore** — просишь Claude Code изучить релевантную часть кода: «посмотри, как сейчас устроена авторизация» — без изменений, только чтение и понимание.\n2. **Plan** — просишь явно сформулировать план: «предложи план добавления двухфакторной аутентификации» — получаешь список шагов до единой строчки кода.\n3. **Code** — только после согласия с планом: «реализуй по этому плану» — теперь агент пишет код, уже опираясь на согласованную структуру.\n4. **Commit** — просишь зафиксировать результат: «закоммить с понятным сообщением» — Claude Code сам формулирует commit message по факту изменений.\n\nДля управления контекстом — команда `/clear` начинает сессию заново (полезно между несвязанными задачами, чтобы старая история не мешала новой), а обсуждение сложной подзадачи стоит явно резюмировать текстом перед тем, как двигаться дальше — это дешевле, чем тащить за собой полную историю исследования.\n\n### 🔗 Смотри в приложении\nРазбор агентного цикла (Explore/Plan/Code как частный случай более общего паттерна) — в статье [«Анатомия агентного цикла Claude Code (Agentic Loop)»](entry:cc-architecture-loops). Готовый фреймворк навыков именно под такую методологию — в разделе Софт: [obra/superpowers](tool:obra/superpowers).\n\n### ⚠️ Частая ошибка новичка\nПросить Claude Code сразу писать код на сложную задачу, минуя явную фазу плана — экономия одного сообщения на входе часто оборачивается более долгой перепиской на исправления результата, который пошёл не в ту сторону.\n\nВторая ошибка — тащить одну и ту же сессию через несколько совершенно не связанных задач подряд без `/clear`. Накопленный контекст от предыдущей задачи может неявно влиять на решения по новой, даже если ты явно не ссылаешься на старую.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 3 «Daily Workflows» — anthropic.skilljar.com/claude-code-101" },
  { id: 303, slug: "guide-code-review", level: 3, title: "Код-ревью с Claude Code", summary: "Как получить полезное ревью изменений — от локального diff до чужого пул-реквеста.", order_in_level: 4, doc_url: "https://anthropic.skilljar.com/claude-code-101", related_entry: null, related_tools: [], related_prompts: [], body_md: "### ❓ Что это\nClaude Code можно попросить проревьюить код так же, как попросить его написать — разница только в задаче: не «сделай», а «проверь и укажи на проблемы». Ревью может касаться локальных незакоммиченных изменений (`git diff`), конкретного файла, всего пул-реквеста через интеграцию с GitHub, или даже чужого кода, который ты просто открыл в терминале.\n\nЭто дополняет, а не заменяет ревью человека — Claude Code хорошо ловит очевидные технические проблемы (пропущенную обработку ошибок, потенциальные race conditions, несоответствие конвенциям проекта), но не заменяет понимание бизнес-контекста, которое есть у живого ревьюера в команде.\n\n### 🎯 Зачем тебе\nПервый проход ревью — рутинная, но необходимая часть разработки: заметить очевидные проблемы до того, как их увидит человек-ревьюер, экономит время всей команды и ускоряет цикл разработки. Особенно полезно перед тем, как выложить пул-реквест — прогнать код через Claude Code первым, поймать очевидное самому, и уже потом отдавать на ревью коллеге, который сможет сосредоточиться на более глубоких архитектурных вопросах.\n\n### 💻 Как это выглядит на практике\nСамый простой сценарий — попросить проверить незакоммиченные изменения прямо в текущей сессии: «прогляди git diff и укажи на проблемы» — Claude Code сам достаёт diff и анализирует его построчно.\n\nБолее формальный запрос — попросить сыграть роль строгого ревьюера, а не просто «посмотри код»: явно указать, что нужен придирчивый разбор, а не общая похвала. Разница в формулировке ощутимо влияет на глубину ревью — «посмотри, всё ли ок» почти всегда даёт более поверхностный ответ, чем «найди 5 конкретных проблем, даже незначительных».\n\nТипичные вещи, которые Claude Code хорошо ловит при ревью:\n- **Пропущенная обработка ошибок** — например, незакрытые try/except или проигнорированный код ответа API.\n- **Несоответствие конвенциям проекта** — если в `CLAUDE.md` описан стиль кода, ревью сверяется именно с ним, а не с общими best practices.\n- **Потенциальные проблемы безопасности** — SQL-инъекции, небезопасная десериализация, утечка секретов в лог.\n- **Излишняя сложность** — код, который решает задачу таким образом, что его сложно поддерживать, даже если формально работает правильно.\n\n### 🔗 Смотри в приложении\nГотовый промпт под жёсткое ревью (не общую похвалу, а конкретные придирки) — [«Жёсткое ревью пулл-реквеста»](prompt:code-rev-pr-review) в разделе Промпты.\n\n### ⚠️ Частая ошибка новичка\nПросить общее «посмотри, всё ли нормально» вместо конкретной задачи ревью — расплывчатый запрос почти всегда даёт расплывчатый, вежливый ответ без реальной пользы. Чем конкретнее сформулирован критерий («найди проблемы с обработкой ошибок», «проверь на соответствие CLAUDE.md»), тем полезнее результат.\n\nВторая ошибка — воспринимать одобрение от Claude Code как гарантию отсутствия проблем. Это первый фильтр, а не финальная инстанция — для критичного кода (платежи, авторизация, работа с личными данными) человеческое ревью всё равно обязательно.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 3 «Daily Workflows» — anthropic.skilljar.com/claude-code-101" },
  { id: 304, slug: "guide-claude-md", level: 3, title: "CLAUDE.md — память проекта, которую Claude Code читает сам", summary: "Один файл в корне репозитория, который избавляет агента от угадывания структуры проекта каждый раз заново.", order_in_level: 5, doc_url: "https://code.claude.com/docs", related_entry: "cc-claude-md-config", related_tools: [], related_prompts: [], body_md: "![](/guide/3/guide-claude-md.svg)\n\n### ❓ Что это\n**CLAUDE.md** — обычный markdown-файл в корне репозитория. Claude Code автоматически читает его в начале каждой сессии, чтобы узнать структуру проекта, команды сборки/тестов и правила стиля кода. Это не какой-то специальный формат с секретным синтаксисом — обычный markdown, который ты бы написал для человека-новичка в проекте, только гораздо короче и суше.\n\nФайл можно (и стоит) держать в git вместе с остальным кодом — тогда его подхватывают все, кто работает над проектом с Claude Code, а не только ты лично.\n\n### 🎯 Зачем тебе\nБез этого файла агент каждый раз заново гадает, каким пакетным менеджером пользуется проект, как запускать тесты, какой стиль кода принят — и либо угадывает верно, либо тратит впустую шаг на пробу и ошибку. Один раз описав это, ты экономишь время и токены на каждой сессии — и получаешь код в едином стиле, а не такой, какой агент придумал по своему усмотрению в этот конкретный раз.\n\nЧем больше в команде людей работает с Claude Code над одним репозиторием, тем ценнее этот файл — он становится единым источником правды про конвенции проекта, вместо того чтобы каждый настраивал агента под себя устно.\n\n### 💻 Как это выглядит на практике\n```markdown\n## Build & Test\n- Install: `npm install`\n- Dev server: `npm run dev`\n- Tests: `npm test`\n\n## Code Style\n- TypeScript, строгая типизация\n- Компоненты — функциональные, с хуками\n```\nДостаточно положить такой файл в корень репозитория — Claude Code подхватит его сам, без дополнительных настроек, при следующем же запуске `claude` в этой папке.\n\n![](/guide/3/guide-claude-md-detail.svg)\n\nЧто имеет смысл включать в CLAUDE.md, помимо базовых команд:\n- **Архитектурные решения, которые не менять без явного запроса** — например, «не трогай логику гейта в auth.py без сверки с документацией».\n- **Специфичные для проекта факты** — какая СУБД используется, какие переменные окружения обязательны, где искать конфигурацию.\n- **Ссылки на внешнюю документацию**, если полная спецификация проекта живёт не в репозитории, а отдельно.\n\nФайл можно (и стоит) обновлять по мере роста проекта — как только Claude Code делает что-то не так из-за незнания конвенции, это сигнал добавить соответствующую строчку в CLAUDE.md, чтобы больше не повторять объяснение вручную.\n\n### 🔗 Смотри в приложении\nГотовый разбор структуры и практических примеров — в статье [«Инструкции проекта через CLAUDE.md»](entry:cc-claude-md-config).\n\n### ⚠️ Частая ошибка новичка\nРаздувать CLAUDE.md на сотни строк с историей проекта и общими рассуждениями. Большой файл забивает контекстное окно и увеличивает стоимость каждого запроса — пиши только сухие факты и команды, а не документацию для людей, которую и так можно найти в README.\n\nВторая ошибка — писать файл один раз и никогда не обновлять, даже когда проект меняется. Устаревший CLAUDE.md, который советует давно отменённые команды или ссылается на удалённые файлы, хуже, чем его отсутствие — агент будет честно следовать написанному, даже если это уже неверно.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 4 «Customizing Claude Code» — anthropic.skilljar.com/claude-code-101; code.claude.com/docs" },
  { id: 305, slug: "guide-subagents", level: 3, title: "Субагенты — отдельные помощники под конкретную задачу", summary: "Как не захламлять основной диалог логами и результатами поиска, отдавая побочные задачи отдельному агенту.", order_in_level: 6, doc_url: "https://code.claude.com/docs/en/sub-agents", related_entry: "cc-architecture-loops", related_tools: [], related_prompts: [], body_md: "### ❓ Что это\n**Субагент** — отдельный AI-помощник внутри Claude Code, заточенный под конкретный тип задачи. У него свой собственный контекст (отдельное «окно памяти»), свой системный промпт и, если нужно, ограниченный набор доступных инструментов. Когда основная сессия встречает задачу, подходящую под описание субагента, она делегирует её — субагент работает независимо и возвращает только итоговый результат, а не весь процесс поиска.\n\nЭто принципиально отличается от того, чтобы просто попросить Claude Code «сделать ещё одну вещь» в той же сессии — субагент физически не засоряет основной контекст побочными деталями своей работы.\n\n### 🎯 Зачем тебе\nЕсли задача предполагает много «шумной» побочной работы — прочитать десяток логов, погуглить по документации, пройтись по файлам в поисках нужного паттерна — весь этот шум обычно не нужен в основном диалоге после того, как найден ответ. Субагент делает эту грязную работу в своём изолированном контексте и возвращает только выжимку — основной диалог остаётся чистым и сфокусированным на текущей задаче, не раздутым логами промежуточного поиска.\n\nЭто также способ контролировать расходы: рутинные субзадачи можно направить на более быструю и дешёвую модель (например, Haiku), оставляя основную сессию на более мощной модели только для действительно сложной части работы.\n\n### 💻 Как это выглядит на практике\nСубагент создаётся как обычный markdown-файл с системным промптом, описанием (по которому Claude Code решает, когда его вызывать) и опциональным ограничением набора доступных инструментов. Дальше он используется автоматически — стоит только сформулировать задачу так, чтобы она подходила под описание субагента, явно вызывать его по имени не обязательно.\n\nТипичные кандидаты на отдельного субагента:\n- **Ресёрчер по кодовой базе** — находит все места, где используется конкретная функция или паттерн, возвращает список без сохранения полного дерева поиска в основном контексте.\n- **Ревьюер логов** — читает длинный вывод тестов или сборки, возвращает только суть: что упало и почему.\n- **Специализированный по языку/фреймворку** — узкий системный промпт под конкретный стек (например, только Rust или только SQL-миграции), с доступом только к нужным для этой ниши инструментам.\n\nСубагенты работают в рамках одной сессии. Если нужно запускать много независимых сессий параллельно и следить за ними из одного места — это уже другая механика (background agents), не субагенты как таковые.\n\n### 🔗 Смотри в приложении\nРазбор агентного цикла и роли субагентов в нём — в статье [«Анатомия агентного цикла Claude Code (Agentic Loop)»](entry:cc-architecture-loops). Готовые библиотеки субагентов на все случаи — в разделе Софт: [VoltAgent — 150+ сабагентов](tool:VoltAgent/awesome-claude-code-subagents) и [wshobson/agents — маркетплейс 194 субагентов](tool:wshobson/agents).\n\n### ⚠️ Частая ошибка новичка\nСоздавать субагента с слишком широким и расплывчатым описанием — Claude Code не поймёт, когда именно его вызывать, и либо будет делать это невпопад, либо вообще проигнорирует. Описание субагента должно быть таким же конкретным, как хороший промпт: «анализирует SQL-миграции на предмет несовместимых изменений», а не «помогает с базой данных».\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 4 «Customizing Claude Code» — anthropic.skilljar.com/claude-code-101; code.claude.com/docs/en/sub-agents" },
  { id: 306, slug: "guide-mcp-basics", level: 3, title: "MCP простыми словами — как Claude подключается к внешним инструментам", summary: "Стандарт, который позволяет Claude работать с базами данных, файлами и сервисами без написания уникальной интеграции под каждый.", order_in_level: 7, doc_url: "https://modelcontextprotocol.io", related_entry: "con-mcp-architecture", related_tools: [], related_prompts: [], body_md: "![](/guide/3/guide-mcp-basics.svg)\n\n### ❓ Что это\n**MCP** (Model Context Protocol) — открытый стандарт связи между Claude и внешними инструментами. MCP-сервер «объявляет», какие у него есть инструменты (например, «прочитать таблицу из базы данных», «создать issue в GitHub», «отправить сообщение в Slack»), а Claude может их вызывать, не требуя отдельной кастомной интеграции под каждый сервис.\n\nТехнически MCP работает по клиент-серверной модели: MCP-клиент (Claude Code, Claude Desktop) обменивается сообщениями с MCP-сервером по стандартизированному протоколу. Ты как пользователь этого обмена не видишь — просто просишь что-то на естественном языке, а вызов нужного инструмента происходит внутри автоматически.\n\n### 🎯 Зачем тебе\nБез MCP каждую интеграцию пришлось бы писать с нуля — отдельный код для подключения к каждой базе данных, каждому API, каждому сервису. С готовым MCP-сервером, например, для Postgres, Claude сразу получает типизированные инструменты для чтения таблиц — установил и подключил, а не написал плагин самостоятельно.\n\nЭкосистема MCP-серверов растёт очень быстро — уже есть готовые серверы для большинства популярных баз данных, облачных хранилищ, систем управления проектами и коммуникационных платформ. Это означает, что в большинстве случаев тебе не придётся писать интеграцию самому — достаточно найти готовый сервер и подключить его.\n\n### 💻 Как это выглядит на практике\nПодключение MCP-сервера в Claude Code — одной командой:\n```bash\nclaude mcp add имя-сервера -- npx -y <mcp-пакет>\nclaude mcp list   # проверить, что подключилось\n```\nПосле подключения в диалоге можно просто попросить: «покажи структуру таблицы users» — и Claude сам вызовет нужный инструмент MCP-сервера, получит результат и ответит на основе реальных данных, а не догадок.\n\n![](/guide/3/guide-mcp-basics-detail.svg)\n\nНесколько типичных категорий MCP-серверов, которые стоит знать:\n- **Серверы для баз данных** — Postgres, MySQL, SQLite: чтение схем, выполнение запросов.\n- **Серверы для файловых систем** — работа с файлами за пределами текущего проекта, если это разрешено настройками.\n- **Серверы для внешних сервисов** — GitHub, Slack, Notion, Google Drive: чтение и создание контента напрямую из диалога.\n- **Серверы для инфраструктуры** — Docker, Kubernetes: просмотр статуса контейнеров и логов (подробнее — на уровне 4).\n\nДля командной работы список подключённых MCP-серверов можно зафиксировать в файле `.mcp.json` в корне репозитория — тогда все участники команды получают одинаковый набор инструментов автоматически, без ручной настройки каждым по отдельности.\n\n### 🔗 Смотри в приложении\nАрхитектура протокола с нуля — в статье [«Архитектура Model Context Protocol с нуля»](entry:con-mcp-architecture). Если хочешь написать свой MCP-сервер — в разделе Софт: [fastmcp — Python-фреймворк сборки MCP-серверов](tool:jlowin/fastmcp).\n\n### ⚠️ Частая ошибка новичка\nПодключать непроверенные MCP-серверы из случайных источников. MCP-сервер — это реальный исполняемый код на твоей машине, который может иметь доступ к файлам, сети или учётным данным. Проверяй исходники перед подключением, особенно если сервер не от известного разработчика или официальной организации.\n\nВторая ошибка — подключать сразу много MCP-серверов «про запас», не используя большинство из них. Каждый подключённый сервер добавляет модели дополнительные инструменты для выбора, и слишком широкий набор редко используемых инструментов может немного снижать точность выбора нужного — разумнее подключать по мере реальной необходимости.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 4 «Customizing Claude Code» — anthropic.skilljar.com/claude-code-101; modelcontextprotocol.io" },
  { id: 307, slug: "guide-hooks", level: 3, title: "Hooks — автоматика, которая срабатывает всегда, а не по памяти", summary: "Как заставить форматирование и проверки выполняться гарантированно, а не зависеть от того, вспомнит ли Claude их запустить.", order_in_level: 8, doc_url: "https://code.claude.com/docs/en/hooks", related_entry: "code-hooks-basics", related_tools: [], related_prompts: [], body_md: "![](/guide/3/guide-hooks.svg)\n\n### ❓ Что это\n**Hooks** — обработчики событий жизненного цикла Claude Code: команда, которая срабатывает в конкретный момент (например, после каждой правки файла, до выполнения bash-команды, в начале сессии) независимо от того, что «решила» сделать модель в этот раз. Это ключевое отличие от простой просьбы «пожалуйста, всегда форматируй код после правок» в CLAUDE.md — просьба может быть проигнорирована или забыта, hook сработает механически, каждый раз, без исключений.\n\nКаждый hook — это связка: **событие** (что произошло) → **matcher** (фильтр — на какие именно действия реагировать) → **действие** (обычно shell-команда). События бывают разных типов: `PreToolUse` срабатывает до выполнения действия и может его заблокировать, `PostToolUse` — после, и может только среагировать на уже случившееся.\n\n### 🎯 Зачем тебе\nФорматирование кода после каждой правки, блокировка опасных команд до их выполнения, запрет коммита без прошедших тестов — всё это работает гарантированно каждый раз, а не зависит от того, вспомнит ли Claude запустить линтер сам в конкретной сессии. Hooks превращают пожелание в правило, которое невозможно случайно пропустить.\n\nЭто особенно ценно для команд: если у проекта есть строгие стандарты (обязательное форматирование, запрет прямых коммитов в main, обязательный прогон тестов), hooks гарантируют соблюдение этих стандартов для всех участников, использующих Claude Code, а не только для тех, кто помнит попросить об этом каждый раз.\n\n### 💻 Как это выглядит на практике\nАвтоформатирование после любой правки файла, `.claude/settings.json`:\n```json\n{\n  \"hooks\": {\n    \"PostToolUse\": [\n      {\n        \"matcher\": \"Write|Edit\",\n        \"hooks\": [{ \"type\": \"command\", \"command\": \"npx prettier --write \\\"$CLAUDE_TOOL_INPUT_FILE_PATH\\\"\" }]\n      }\n    ]\n  }\n}\n```\nПосле каждой правки файла эта команда запустится сама, без напоминаний.\n\n![](/guide/3/guide-hooks-detail.svg)\n\nДругие практические примеры использования hooks:\n- **Блокировка опасных команд** — `PreToolUse` может проверить, не содержит ли команда `rm -rf`, и отклонить выполнение до того, как оно случится.\n- **Обязательный прогон тестов перед коммитом** — hook на событие коммита запускает тестовый набор и блокирует коммит при провале.\n- **Уведомления** — например, звуковой сигнал по завершении длинной задачи, чтобы не следить за терминалом постоянно.\n- **Логирование действий** — запись всех выполненных команд в отдельный файл для аудита, что именно агент делал в сессии.\n\nMatcher поддерживает регулярные выражения, так что можно точечно настраивать, на какие именно инструменты и файлы реагировать — например, применять форматирование только к `.ts`-файлам, игнорируя остальные.\n\n### 🔗 Смотри в приложении\nБазовые типы событий и примеры конфигов — в статье [«Hooks в Claude Code: автоматические триггеры на события»](entry:code-hooks-basics). Полигон с примерами всех 13 типов хуков — в разделе Софт: [disler/claude-code-hooks-mastery](tool:disler/claude-code-hooks-mastery).\n\n### ⚠️ Частая ошибка новичка\nКласть такие правила только в свой личный конфиг, а не в `.claude/settings.json` проекта. Личный конфиг работает только у тебя — если хочешь, чтобы гарантия действовала для всей команды, правило нужно закоммитить в проект, чтобы оно применялось у каждого, кто клонирует репозиторий и запускает Claude Code.\n\nВторая ошибка — путать `PreToolUse` и `PostToolUse` по назначению. `PostToolUse` может дать обратную связь и что-то поправить постфактум, но не может отменить уже выполненное действие — для реальной блокировки опасной команды до её выполнения нужен именно `PreToolUse`, иначе защита сработает слишком поздно.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code 101», Module 4 «Customizing Claude Code» — anthropic.skilljar.com/claude-code-101; code.claude.com/docs/en/hooks" },
  { id: 308, slug: "guide-permissions", level: 3, title: "Permissions — не давай агенту делать всё подряд без спроса", summary: "Как настроены подтверждения для опасных команд и почему их не стоит отключать.", order_in_level: 9, doc_url: "https://code.claude.com/docs", related_entry: "cc-permissions-security", related_tools: [], related_prompts: [], body_md: "![](/guide/3/guide-permissions.svg)\n\n### ❓ Что это\nСлой **Permissions** в Claude Code ограничивает, что агент может делать без твоего явного разрешения. По умолчанию он может читать и менять файлы текущего проекта, но для запуска bash-команд, установки пакетов или сетевых запросов спрашивает подтверждение. Это встроенный уровень безопасности между «агент придумал, что делать» и «агент реально это сделал» — важная граница, когда речь идёт о реальном коде на твоей машине, а не просто тексте в чате.\n\nУровень строгости настраивается — можно сделать агента более осторожным (спрашивать буквально на каждый шаг) или более автономным (доверять больше и меньше прерываться), в зависимости от того, насколько ты доверяешь конкретной задаче и проекту.\n\n### 🎯 Зачем тебе\nБез этого контроля ошибка в сгенерированном скрипте может выполнить опасную команду или случайно перезаписать системный файл. Permissions создают безопасную «песочницу» вокруг .env, SSH-ключей и остальной системы за пределами проекта — агент физически не сможет выйти за границы дозволенного без твоего явного «да».\n\nЭто особенно важно, учитывая, что Claude Code способен работать достаточно автономно — он может выполнить несколько шагов подряд без паузы, и без слоя разрешений одна неверно интерпретированная задача теоретически могла бы привести к цепочке нежелательных действий.\n\n### 💻 Как это выглядит на практике\nПри попытке выполнить команду Claude Code спрашивает:\n```\nЗапрашивает разрешение на выполнение:\n$ npm install some-package\n\n[Y] Разрешить один раз\n[A] Разрешать всегда в этой сессии\n[N] Отклонить\n[Q] Выйти\n```\nТы решаешь в моменте — разово, на всю сессию, или отклонить вовсе.\n\n![](/guide/3/guide-permissions-detail.svg)\n\nПрактические рекомендации по уровням доверия:\n- **Чтение файлов проекта** — обычно можно разрешать свободно, это самая безопасная категория действий.\n- **Правка файлов внутри проекта** — разумно проверять диф перед подтверждением, особенно на первых порах знакомства с инструментом.\n- **Установка новых зависимостей** — стоит подтверждать вручную каждый раз, а не выдавать блан-карт на сессию, особенно если название пакета незнакомое.\n- **Сетевые запросы и системные команды за пределами проекта** — самая чувствительная категория, где лучше не спешить с автоматическим разрешением.\n\nСо временем, освоившись и выработав доверие к конкретному проекту и типу задач, можно постепенно ослаблять уровень подтверждений — но начинать разумно с максимально строгого режима.\n\n### 🔗 Смотри в приложении\nПодробный разбор режимов доступа и рекомендаций по безопасности — в статье [«Permissions и безопасность хоста»](entry:cc-permissions-security).\n\n### ⚠️ Частая ошибка новичка\nОтключать ручные подтверждения «чтобы не отвлекаться», особенно в проекте с непроверенными сторонними зависимостями. Агент может случайно прочитать и выполнить вредоносный код из чужого пакета без твоего ведома — не отключай подтверждения там, где не уверен на 100% в безопасности зависимостей.\n\nВторая ошибка — противоположная: разрешать всё подряд не глядя, просто нажимая «Y» на автомате, не читая, что именно запрашивается. Смысл подтверждения теряется, если оно превращается в бездумный рефлекс — стоит хотя бы бегло читать команду перед тем, как её одобрить.\n\n### 🔗 Официальный источник\ncode.claude.com/docs (безопасность — не отдельный модуль официального курса «Claude Code 101», но встроена в весь курс как сквозная тема)" },
  { id: 400, slug: "guide-agentic-patterns", level: 4, title: "Агентные паттерны — Router, Worker, Validator", summary: "Как разбить одну сложную задачу на цепочку специализированных вызовов модели вместо одного большого запроса. По мотивам Module 10 курса Anthropic Academy «Building with the Claude API».", order_in_level: 1, doc_url: "https://anthropic.skilljar.com/claude-with-the-anthropic-api", related_entry: "con-agentic-design-patterns", related_tools: [], related_prompts: [], body_md: "![](/guide/4/guide-agentic-patterns.svg)\n\n### ❓ Что это\nАгентные паттерны — архитектурные шаблоны, разбивающие одну сложную задачу на каскад изолированных вызовов модели, где каждый шаг выполняет строго свою роль: маршрутизацию, генерацию, или финальную проверку качества. Вместо одного гигантского запроса «сделай всё сразу», задача проходит через несколько специализированных «станций», каждая из которых хорошо справляется со своей узкой частью.\n\nЭто не теоретическая абстракция — именно так устроены многие реальные production-системы на базе Claude: не один универсальный вызов, а конвейер из нескольких, каждый со своей ролью, промптом и иногда даже своей моделью (например, быстрая Haiku для маршрутизации и мощная Opus для финальной генерации).\n\n### 🎯 Зачем тебе\nПопытка решить комплексную задачу одним большим запросом часто приводит к потере фокуса — модель распыляется и на середине забывает часть требований, особенно если инструкция содержит много разных, слабо связанных условий одновременно. Разделение труда между отдельными ролями даёт более предсказуемый результат на каждом шаге, потому что каждый вызов решает одну простую, хорошо очерченную задачу, а не жонглирует пятью сразу.\n\nДополнительный плюс — такую систему проще отлаживать. Если конвейер даёт плохой результат, легче найти, на каком именно шаге что-то пошло не так, чем разбираться, что случилось внутри одного монолитного запроса со сложной составной инструкцией.\n\n### 💻 Как это выглядит на практике\n```\nПользователь (задача)\n      ↓\nOrchestrator — разбивает на подзадачи\n      ↓\n  ┌───┴───┐\n  ↓       ↓\nCoder   QA-проверка\n  └───┬───┘\n      ↓\nФинальный валидатор\n```\n\n![](/guide/4/guide-agentic-patterns-detail.svg)\n\nНесколько устоявшихся паттернов, которые стоит знать:\n- **Router** — первый вызов классифицирует запрос и направляет его к нужному специализированному обработчику (например, «это вопрос про биллинг» → отдельная логика, «это техническая проблема» → другая).\n- **Orchestrator-Workers** — центральный вызов разбивает сложную задачу на подзадачи и распределяет их между несколькими специализированными вызовами, а затем собирает результаты воедино.\n- **Evaluator-Optimizer** — один вызов генерирует черновик, второй его критически оценивает и даёт обратную связь, цикл повторяется, пока качество не станет достаточным.\n\nНа практике это можно собрать через субагентов Claude Code — отдельные подпроцессы с узкой ролью, вызываемые основным агентом по мере необходимости, каждый со своим системным промптом под конкретную задачу (см. урок про субагентов на уровне 3).\n\n### 🔗 Смотри в приложении\nРазбор одного из этих паттернов «изнутри» самого Claude Code — в статье [«Анатомия агентного цикла Claude Code (Agentic Loop)»](entry:cc-architecture-loops).\n\n### ⚠️ Частая ошибка новичка\nСтроить длинную цепочку агентов там, где хватило бы одного хорошо сформулированного запроса. Каждый дополнительный шаг увеличивает время ответа и стоимость сессии — начинай с простого и усложняй только тогда, когда базовый подход реально перестаёт справляться, а не заранее «на всякий случай» проектируй сложную многоступенчатую систему.\n\nВторая ошибка — недооценивать важность чёткого контракта между шагами. Если Orchestrator передаёт Worker'у нечётко сформулированную подзадачу, ошибка размножается по всей цепочке — качество разбиения на первом шаге определяет качество всего результата на выходе.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Building with the Claude API», Module 10 «Agents and Workflows» — anthropic.skilljar.com/claude-with-the-anthropic-api; anthropic.com/research — Building Effective Agents" },
  { id: 401, slug: "guide-context-window", level: 4, title: "Контекстное окно — почему середина промпта запоминается хуже", summary: "Эффект затухания внимания в длинном контексте и как располагать важное, чтобы модель это точно не пропустила. По мотивам «Controlling Context» из курса Anthropic Academy «Claude Code in Action».", order_in_level: 2, doc_url: "https://anthropic.skilljar.com/claude-code-in-action", related_entry: "con-context-window-limits", related_tools: [], related_prompts: [], body_md: "![](/guide/4/guide-context-window.svg)\n\n### ❓ Что это\nКонтекстное окно — «оперативная память» модели на один диалог: весь текст, который модель «видит» и учитывает при генерации ответа, включая системные инструкции, историю переписки, прикреплённые файлы. Несмотря на большой номинальный размер (у современных моделей Claude — до миллиона токенов), при работе с длинным контекстом проявляется эффект **Lost in the Middle**: модель лучше всего помнит начало (системные инструкции) и конец (последние сообщения) промпта, хуже — середину.\n\nЭто не баг конкретной модели, а общее свойство архитектуры трансформеров, наблюдаемое у большинства современных языковых моделей в той или иной степени — знание об этом эффекте позволяет осознанно проектировать структуру больших промптов, а не наивно верить, что «раз влезло в окно — значит, точно учтено полностью».\n\n### 🎯 Зачем тебе\nЕсли бездумно залить в контекст сотни файлов вперемешку, модель может проигнорировать важное правило, спрятанное где-то в середине массива данных — при этом уверенно утверждая, что «всё учла», потому что формально файл был в контексте. Понимание этого эффекта — уже само по себе инструмент: зная про него, ты можешь сознательно структурировать длинные промпты так, чтобы критичное не потерялось.\n\nЭто особенно важно на уровне мастерства — когда ты собираешь сложные системы, где Claude обрабатывает большие объёмы данных: код целого репозитория, длинную документацию, историю долгого диалога. Ошибка в размещении важной инструкции может стоить много времени на отладку «почему модель это проигнорировала», хотя причина — чисто структурная.\n\n### 💻 Как это выглядит на практике\nПорядок частей промпта имеет значение:\n```\nНачало: жёсткие правила — читаются идеально\nСередина: тяжёлые сырые данные — зона риска\nКонец: финальный фокус запроса — приоритет\n```\nСамые важные инструкции стоит класть в начало или конец, а не прятать посреди большого массива текста или файлов.\n\n![](/guide/4/guide-context-window-detail.svg)\n\nПрактические техники работы с этим эффектом:\n- **Дублирование критичных инструкций** — если правило действительно важно, повтори его и в начале, и в конце промпта, а не полагайся на одно упоминание где-то в середине.\n- **Явные разделители секций** — используй XML-теги или markdown-заголовки, чтобы модели было проще ориентироваться в структуре длинного контекста, даже если конкретный фрагмент физически лежит в середине.\n- **Суммаризация вместо сырых данных** — если объём действительно большой, иногда полезнее дать сжатое резюме, чем полный сырой текст, особенно для частей, не требующих дословной точности.\n- **Явный фокус запроса в конце** — конкретный вопрос или задача в последнем сообщении диалога получает наибольший приоритет внимания модели.\n\n### ⚠️ Частая ошибка новичка\nДержать контекст переполненным без необходимости «на всякий случай». Это не только рискует потерять важное в середине, но и увеличивает время до первого токена ответа, а также стоимость запроса — используй сжатие истории или `/compact` в Claude Code, когда сессия становится тяжёлой, вместо того чтобы копить контекст бесконечно.\n\nВторая ошибка — недооценивать этот эффект и считать, что раз модель формально «видела» файл или инструкцию в контексте, значит она гарантированно их учла с равным приоритетом. На практике позиция информации в промпте — не нейтральный фактор, а один из рычагов управления качеством ответа, наравне с самой формулировкой задачи.\n\n### 🔗 Смотри в приложении\nБолее широкий разбор ограничений контекстного окна — в статье [«Контекстное окно и эффект затухания внимания»](entry:con-context-window-limits). Если хочешь видеть, сколько контекста/токенов реально расходуется в сессиях Claude Code — в разделе Софт: [ccusage — CLI-анализ расхода токенов](tool:ryoppippi/ccusage).\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code in Action», Module 3 «Controlling Context» — anthropic.skilljar.com/claude-code-in-action; anthropic.com/research" },
  { id: 402, slug: "guide-custom-commands", level: 4, title: "Свои слэш-команды — автоматизация повторяющихся запросов", summary: "Сохранённые под своей командой промпты, чтобы не набирать одно и то же вручную каждый раз.", order_in_level: 3, doc_url: "https://anthropic.skilljar.com/claude-code-in-action", related_entry: "cc-slash-commands", related_tools: [], related_prompts: [], body_md: "### ❓ Что это\nВстроенные слэш-команды вроде `/clear` или `/help` — не единственные, которые понимает Claude Code. Можно создавать **свои** — markdown-файл в папке `.claude/commands/` становится доступен как `/имя-файла`, и при вызове его содержимое подставляется как промпт, с возможностью передать дополнительные аргументы.\n\nЭто простой, но мощный способ зафиксировать часто повторяющийся запрос один раз и вызывать его одним словом вместо того, чтобы каждый раз формулировать заново.\n\n### 🎯 Зачем тебе\nЕсли ты регулярно просишь Claude Code об одном и том же — например, «проверь этот файл на соответствие нашему стайлгайду и напиши тесты» — есть смысл зафиксировать это как команду `/check-and-test`, а не набирать длинную инструкцию каждый раз заново. Экономия не только в наборе текста: команда гарантирует, что формулировка задачи остаётся одинаковой каждый раз, а не немного плывёт от сессии к сессии.\n\nДля команд это способ зафиксировать общий процесс — если у всей команды есть свой `/review-pr`, каждый участник получает одинаково тщательное ревью по одному и тому же чек-листу, а не по тому, что лично вспомнил попросить в моменте.\n\n### 💻 Как это выглядит на практике\nФайл `.claude/commands/review.md`:\n```markdown\nПроверь текущий diff на:\n- Пропущенную обработку ошибок\n- Несоответствие стилю проекта из CLAUDE.md\n- Потенциальные проблемы безопасности\n\nДай список конкретных проблем, без общих слов.\n```\nПосле этого команда `/review` в терминале запускает именно этот промпт — без необходимости набирать инструкцию заново.\n\nКоманды поддерживают аргументы — можно передать что-то дополнительное при вызове (например, `/review src/auth.py`, чтобы уточнить конкретный файл), которое подставляется в заранее заданное место шаблона.\n\nКоманды, сохранённые в `.claude/commands/` в корне репозитория, попадают в git вместе с остальным кодом — весь, кто клонирует проект, получает те же самые команды автоматически, без ручной настройки.\n\n### 🔗 Смотри в приложении\nПолный справочник встроенных и пользовательских слэш-команд — в статье [«Справочник по slash-командам»](entry:cc-slash-commands).\n\n### ⚠️ Частая ошибка новичка\nДержать полезные команды только в личном (не проектном) конфиге — тогда ими пользуешься только ты, а не вся команда. Если команда полезна не только лично тебе, а для процесса в целом — стоит положить её в `.claude/commands/` внутри репозитория и закоммитить, а не оставлять в личных настройках.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code in Action», Module 3 «Controlling Context» (Custom commands) — anthropic.skilljar.com/claude-code-in-action" },
  { id: 403, slug: "guide-headless-automation", level: 4, title: "Headless-режим и Claude Code SDK — без человека за клавиатурой", summary: "Как запустить агента автономно через SDK, например внутри CI/CD, чтобы он сам ревьюил каждый Pull Request. По мотивам «The Claude Code SDK» из курса Anthropic Academy «Claude Code in Action».", order_in_level: 4, doc_url: "https://anthropic.skilljar.com/claude-code-in-action", related_entry: "cc-headless-ci-cd", related_tools: [], related_prompts: [], body_md: "![](/guide/4/guide-headless-automation.svg)\n\n### ❓ Что это\n**Headless-режим** запускает Claude Code без интерактивного диалога: задача передаётся аргументом командной строки, агент отрабатывает автономно от начала до конца и возвращает код завершения — 0 при успехе, 1 при ошибке, как любая обычная CLI-утилита в скрипте или пайплайне. Никто не сидит и не нажимает «да, разрешаю» на каждый шаг — весь процесс происходит без участия человека.\n\nЭто принципиально иной режим использования по сравнению с интерактивной сессией: headless-запуск создан специально для встраивания в автоматизированные процессы, где нужен предсказуемый результат без диалога.\n\n### 🎯 Зачем тебе\nЭто позволяет встроить агента в пайплайн CI/CD — на каждый Pull Request автоматически запускается ревью кода, поиск критичных багов, или генерация недостающих тестов, ещё до того, как к делу подключится человек-ревьюер. Это не заменяет ревью человека полностью, а фильтрует очевидные проблемы заранее, экономя время команды на рутинной части проверки.\n\nHeadless-режим также полезен для массовых пакетных задач — например, прогнать одну и ту же трансформацию по сотне файлов в скрипте, без необходимости подтверждать каждый файл вручную в интерактивном режиме.\n\n### 💻 Как это выглядит на практике\nШаг в GitHub Actions:\n```yaml\n- uses: actions/checkout@v4\n- run: npm install -g @anthropic-ai/claude-code\n- env:\n    ANTHROPIC_API_KEY: ${{ secrets.ANTHROPIC_API_KEY }}\n  run: claude-code --non-interactive \"Проверь diff, найди критичные баги, верни код 1 если есть\"\n```\nКаждый PR автоматически прогоняется через агента без ручного запуска.\n\n![](/guide/4/guide-headless-automation-detail.svg)\n\nТипичные сценарии использования headless-режима:\n- **Автоматическое ревью PR** — как в примере выше, блокирует мерж при обнаружении критичных проблем.\n- **Генерация недостающих тестов** — по расписанию или по триггеру находит непокрытый тестами код и предлагает тесты.\n- **Массовые миграции** — например, обновление устаревшего API во всех файлах проекта разом, как одна автоматизированная задача.\n- **Автоматическая документация** — генерация или обновление README и docstring по факту изменений в коде.\n\nРезультат работы headless-агента обычно логируется целиком — это полезно для последующего разбора, что именно он сделал и на основе чего принял решение.\n\nПомимо флага `--non-interactive` в CLI, тот же headless-режим доступен программно через **Claude Code SDK** — библиотеку, которая даёт более гибкий контроль из кода (Python/TypeScript), чем просто вызов CLI-команды из shell-скрипта: явная обработка каждого шага сессии, структурированный доступ к результатам, более тонкое управление разрешениями из кода вызывающего приложения.\n\n### 🔗 Смотри в приложении\nПодробный разбор автоматизации в CI/CD с примерами конфигов — в статье [«Headless-режим и интеграция в CI/CD»](entry:cc-headless-ci-cd). Официальный Python SDK для программного управления агентом — в разделе Софт: [claude-agent-sdk-python](tool:anthropics/claude-agent-sdk-python).\n\n### ⚠️ Частая ошибка новичка\nНе ограничивать бюджет токенов и таймаут шага. Если сборка циклически падает, headless-агент может бесконечно пытаться её исправить и выжечь весь баланс API за считанные минуты — всегда ставь явные лимиты на количество попыток и время выполнения, особенно при первом внедрении в незнакомый пайплайн.\n\nВторая ошибка — давать headless-агенту слишком широкие полномочия без промежуточного контроля, особенно на первых порах. Разумная практика — начинать с того, что агент только предлагает изменения (например, комментирует PR), а не сразу мержит их автоматически, пока не накопится доверие к качеству его решений в конкретном проекте.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Claude Code in Action», Module 4 «Hooks and the SDK» — anthropic.skilljar.com/claude-code-in-action; code.claude.com/docs" },
  { id: 404, slug: "guide-mcp-docker", level: 4, title: "Свой MCP-сервер для Docker — управление контейнерами из Claude Code", summary: "Как дать агенту доступ к логам и статусу локальных Docker-контейнеров прямо из сессии.", order_in_level: 5, doc_url: "https://code.claude.com/docs/en/mcp-quickstart", related_entry: "cc-mcp-docker-setup", related_tools: [], related_prompts: [], body_md: "![](/guide/4/guide-mcp-docker.svg)\n\n### ❓ Что это\nИнтеграция Claude Code с локальным Docker через MCP-сервер даёт агенту типизированные инструменты для сборки образов, просмотра статуса контейнеров, чтения логов и перезапуска — не выходя из текущей сессии. Это конкретный практический пример того, как MCP (с уровня 3) применяется к реальной инфраструктурной задаче, а не просто к работе с текстом или кодом.\n\nВместо того чтобы объяснять агенту голосом, что происходит в контейнерах, он получает прямой доступ к тем же данным, что видишь ты сам в терминале — статусы, логи, метрики использования ресурсов.\n\n### 🎯 Зачем тебе\nНе нужно постоянно переключаться между терминалом с сессией Claude Code и соседней вкладкой с `docker compose logs -f`. Можно попросить агента самому найти причину падения контейнера по логам и поправить конфиг — весь цикл диагностики и исправления происходит внутри одного диалога, без ручного копирования логов туда-сюда.\n\nЭто особенно полезно при отладке сложных многоконтейнерных систем, где проблема может быть не в конкретном сервисе, а в их взаимодействии — агент может одновременно смотреть логи нескольких контейнеров и сопоставлять их по времени, что вручную делать утомительно.\n\n### 💻 Как это выглядит на практике\nПодключение через официальную команду:\n```bash\nclaude mcp add docker -- npx -y <docker-mcp-пакет>\nclaude mcp list\n```\nДля командной работы — зафиксируй в `.mcp.json` в корне проекта (коммитится в git, применяется у всей команды):\n```json\n{\n  \"mcpServers\": {\n    \"docker\": { \"type\": \"stdio\", \"command\": \"npx\", \"args\": [\"-y\", \"<docker-mcp-пакет>\"] }\n  }\n}\n```\n\n![](/guide/4/guide-mcp-docker-detail.svg)\n\nПрактические сценарии, где это реально экономит время:\n- **«Почему упал контейнер backend?»** — агент сам смотрит логи и exit-код, находит причину, предлагает фикс конфигурации.\n- **«Собери образ и запусти локально»** — весь цикл сборки и запуска происходит по одной фразе, без ручного набора команд.\n- **«Сравни, что изменилось в логах после последнего деплоя»** — агент может сопоставить состояние до и после изменений.\n\nКак и с любым MCP-сервером, точное имя npm-пакета стоит сверять в актуальном каталоге MCP-серверов перед использованием — экосистема быстро развивается, конкретные пакеты появляются и устаревают.\n\n### 🔗 Смотри в приложении\nПошаговая настройка именно этой интеграции — в статье [«Подключение Docker MCP-сервера в Claude Code»](entry:cc-mcp-docker-setup). Официальный Docker-шлюз для MCP-серверов в контейнерах — в разделе Софт: [docker/mcp-gateway](tool:docker/mcp-gateway).\n\n### ⚠️ Частая ошибка новичка\nОставлять агента в headless-режиме с доступом к Docker без присмотра. Проброс доступа к Docker-сокету фактически даёт root-права на хосте — деструктивная команда очистки может снести все локальные базы и кэши образов разом, если агент интерпретирует задачу слишком буквально или ошибочно.\n\nВторая ошибка — давать этот доступ в проде без крайней необходимости. MCP-интеграция с Docker создана прежде всего для локальной разработки и отладки — для продакшен-инфраструктуры разумнее использовать более узкие, специально ограниченные права, а не тот же widescope доступ, что удобен на локальной машине.\n\n### 🔗 Официальный источник\ncode.claude.com/docs/en/mcp-quickstart" },
  { id: 405, slug: "guide-prompt-caching", level: 4, title: "Prompt Caching — снижение затрат до 90% на повторяющемся контексте", summary: "Как не платить полную цену за один и тот же большой контекст на каждом запросе к API. По мотивам Module 7 курса Anthropic Academy «Building with the Claude API».", order_in_level: 6, doc_url: "https://anthropic.skilljar.com/claude-with-the-anthropic-api", related_entry: "api-prompt-caching", related_tools: [], related_prompts: [], body_md: "![](/guide/4/guide-prompt-caching.svg)\n\n### ❓ Что это\n**Prompt Caching** — технология Anthropic API, позволяющая временно кэшировать тяжёлые неизменяемые блоки контекста. Повторные запросы читают их из кэша вместо полного повторного прогона через модель — модель не «пережёвывает» один и тот же большой текст заново на каждом запросе, если он не изменился.\n\nЭто относится к использованию Claude через API (для своих приложений и интеграций), а не к обычному использованию claude.ai — в вебе кэширование происходит автоматически и прозрачно для тебя, а вот при работе с API за него нужно явно отвечать в коде.\n\n### 🎯 Зачем тебе\nЕсли бот через API анализирует большой репозиторий или документацию, без кэширования каждый запрос стоит полной цены за весь контекст заново — даже если единственное, что поменялось, это последний вопрос пользователя, а весь остальной контекст (документация, системные инструкции, история) идентичен предыдущему запросу. С кэшем полная цена платится один раз, все последующие обращения к тому же блоку — на порядок дешевле, вплоть до 90% экономии заявленной Anthropic.\n\nЭто критично важно для production-приложений с постоянным, объёмным системным контекстом — чат-боты поддержки с большой базой знаний, ассистенты по кодовой базе, любые системы, где один и тот же большой блок контекста используется снова и снова в разных запросах.\n\n### 💻 Как это выглядит на практике\n```python\nresponse = client.messages.create(\n    model=\"claude-sonnet-5\",\n    max_tokens=1024,\n    system=[{\n        \"type\": \"text\",\n        \"text\": \"Вся документация проекта...\",\n        \"cache_control\": {\"type\": \"ephemeral\"}\n    }],\n    messages=[{\"role\": \"user\", \"content\": \"Найди баг в схеме БД\"}]\n)\n```\nБлок с `cache_control` кэшируется, следующие запросы с тем же блоком обходятся заметно дешевле.\n\n![](/guide/4/guide-prompt-caching-detail.svg)\n\nПрактические рекомендации по применению:\n- **Кэшируй самое стабильное** — системные инструкции, справочная документация, большие кодовые базы — то, что не меняется от запроса к запросу.\n- **Не кэшируй то, что меняется каждый раз** — сам пользовательский вопрос кэшировать бессмысленно, он и так уникален на каждый запрос.\n- **Структурируй промпт так, чтобы кэшируемая часть шла в начале** — это стандартная практика, совпадающая с тем, что ты уже знаешь про контекстное окно из прошлого урока: стабильные, важные блоки логично располагать в начале.\n- **Мониторь фактическую экономию** — в ответе API возвращается информация о том, сколько токенов было прочитано из кэша, а сколько обработано заново — стоит явно проверять эти цифры, а не считать кэширование работающим по умолчанию.\n\n### ⚠️ Частая ошибка новичка\nЗабывать, что кэш живёт всего 5 минут с момента последнего запроса (есть платная опция часового кэша по повышенной цене записи). Если запросы идут реже — кэш просто не успевает сработать, и ты платишь полную цену каждый раз, как будто кэширования и не было вовсе, хотя код формально его использует.\n\nВторая ошибка — пытаться кэшировать слишком маленькие блоки контекста. Есть минимальный порог объёма для эффективного кэширования (порядка 1–2 тысяч токенов у Sonnet/Opus, больше у Haiku — точный порог стоит сверять в актуальной документации перед реализацией) — кэширование пары предложений просто не даст заметной экономии и добавит ненужную сложность коду без реальной пользы.\n\n### 🔗 Смотри в приложении\nМеханика кэша, TTL и цифры экономии — в статье [«Prompt Caching: снижение затрат до 90%»](entry:api-prompt-caching). Прикинуть, сколько токенов реально уходит на твой контекст — калькулятор токенов на Home.\n\n### 🔗 Официальный источник\nAnthropic Academy, курс «Building with the Claude API», Module 7 «Features of Claude» — anthropic.skilljar.com/claude-with-the-anthropic-api; platform.claude.com — Prompt Caching" },
];
let mockGuideProgress = new Set([1]);

export async function mockFetch(path, options = {}) {
  await new Promise((r) => setTimeout(r, 250));

  if (path === "/gate/check" || path === "/gate/recheck") return { subscribed: true, user: { tg_id: 1, username: "dev" } };
  if (path === "/home") {
    return {
      counts: { entries_count: 30, tools_count: 18, prompts_count: 33 },
      stats: {
        entries_count: 30, tools_count: 44, prompts_count: 33,
        total_copies: 1287, users_count: 512, subscribers: 2140,
      },
      top_prompts: prompts.map((p) => ({ slug: p.slug, title: p.title, category: p.category, copies_count: p.copies_count })),
      recent_entries: entries.map((e) => ({ slug: e.slug, title: e.title, updated_at: e.updated_at })),
    };
  }
  if (path === "/favorites/ids") return mockFavorites.map((f) => `${f.item_type}:${f.item_id}`);
  if (path === "/favorites/toggle") {
    const body = JSON.parse(options.body || "{}");
    const i = mockFavorites.findIndex((f) => f.item_type === body.item_type && f.item_id === body.item_id);
    if (i >= 0) { mockFavorites.splice(i, 1); return { favorited: false }; }
    mockFavorites.push(body);
    return { favorited: true };
  }
  if (path === "/favorites") {
    return mockFavorites.map((f) => {
      const src = f.item_type === "entry" ? entries : f.item_type === "tool" ? tools : f.item_type === "guide" ? guideLessons : prompts;
      const item = src.find((x) => x.id === f.item_id);
      return item && {
        item_type: f.item_type, item_id: f.item_id,
        title: item.title || item.name, subtitle: item.summary || item.description_ru || item.comment,
        entry_slug: f.item_type === "entry" ? item.slug : null,
        prompt_slug: f.item_type === "prompt" ? item.slug : null,
        tool_repo: f.item_type === "tool" ? item.repo : null,
        guide_slug: f.item_type === "guide" ? item.slug : null,
        guide_level: f.item_type === "guide" ? item.level : null,
      };
    }).filter(Boolean);
  }
  if (path.startsWith("/components/")) return components.find((c) => path.endsWith(c.slug)) || components[0];
  if (path.startsWith("/components")) return components;
  if (path.startsWith("/cheatsheets/")) return cheatsheets.find((c) => path.endsWith(c.slug)) || cheatsheets[0];
  if (path.startsWith("/cheatsheets")) return cheatsheets.map(({ body_md, ...rest }) => rest);
  if (path.endsWith("/rate")) {
    const value = JSON.parse(options.body || "{}").value;
    entryBody.my_rating = entryBody.my_rating === value ? null : value;
    if (value === 1) entryBody.likes += entryBody.my_rating === 1 ? 1 : -1;
    if (value === -1) entryBody.dislikes += entryBody.my_rating === -1 ? 1 : -1;
    return { likes: entryBody.likes, dislikes: entryBody.dislikes, my_rating: entryBody.my_rating };
  }
  if (path.startsWith("/entries/")) {
    const slug = path.slice("/entries/".length);
    if (slug === "con-agentic-design-patterns") {
      return {
        id: 4,
        slug: "con-agentic-design-patterns",
        section: "theory",
        title: "Агентные паттерны: Router, Orchestrator, Subagents",
        doc_url: "https://docs.claude.com/en/docs_site_map.md",
        updated_at: "2026-07-11",
        likes: 5,
        dislikes: 0,
        my_rating: null,
        body_md: "### ❓ Что это\nОбзор архитектурных шаблонов разделения сложной задачи между специализированными вызовами модели.\n\n```mermaid\ngraph TD\n  Query([Запрос пользователя]) --> Router{Router}\n  \n  Router -->|Простой запрос| Single[Single Call]\n  Router -->|Сложный запрос| Orchestrator[Orchestrator]\n  \n  Orchestrator --> Sub1[Subagent 1: Разработчик]\n  Orchestrator --> Sub2[Subagent 2: Тестировщик]\n  \n  click Router href \"entry:con-building-effective-agents\" \"Подробнее про Workflow\"\n  click Orchestrator href \"entry:cc-agent-teams\" \"Смотреть команды агентов\"\n  click Sub1 href \"entry:cc-skills-authoring\" \"Как писать скиллы\"\n```\n\n### 🎯 Зачем тебе\nПроектирование систем."
      };
    }
    return entryBody;
  }
  if (path.startsWith("/entries")) {
    const q = new URLSearchParams(path.split("?")[1] || "");
    return entries.filter((e) =>
      (!q.get("section") || e.section === q.get("section")) &&
      (!q.get("group") || e.group_slug === q.get("group")));
  }
  if (path.startsWith("/tools/")) {
    const slug = path.slice("/tools/".length);
    return tools.find((t) => t.repo.replace("/", "__") === slug) || {};
  }
  if (path.startsWith("/tools")) {
    const q = new URLSearchParams(path.split("?")[1] || "");
    return tools.filter((t) => !q.get("category") || t.category === q.get("category"));
  }
  if (path.startsWith("/prompts") && options.method === "POST") return { copies_count: 143 };
  if (path.startsWith("/prompts")) return prompts;
  if (path.startsWith("/search")) {
    const q = new URLSearchParams(path.split("?")[1]).get("q") || "";
    return {
      entries: entries.filter((e) => e.title.toLowerCase().includes(q.toLowerCase())).map((e) => ({ ...e, type: "entry" })),
      tools: tools.filter((t) => t.name.toLowerCase().includes(q.toLowerCase())).map((t) => ({ ...t, type: "tool" })),
      prompts: prompts.filter((p) => p.title.toLowerCase().includes(q.toLowerCase())).map((p) => ({ ...p, type: "prompt" })),
      guide: guideLessons.filter((l) => l.title.toLowerCase().includes(q.toLowerCase())).map((l) => ({ ...l, type: "guide" })),
      components: components.filter((c) => c.title.toLowerCase().includes(q.toLowerCase()) || c.summary.toLowerCase().includes(q.toLowerCase())).map((c) => ({ ...c, type: "component" })),
    };
  }
  if (path === "/feedback") return { sent: true };
  if (path.startsWith("/guide/lessons/") && path.endsWith("/complete")) {
    const slug = path.split("/")[3];
    const lesson = guideLessons.find((l) => l.slug === slug);
    if (lesson) mockGuideProgress.add(lesson.id);
    return { completed: true };
  }
  if (path.startsWith("/guide/lessons/")) {
    const slug = path.slice("/guide/lessons/".length);
    const lesson = guideLessons.find((l) => l.slug === slug);
    return lesson ? { ...lesson, completed: mockGuideProgress.has(lesson.id) } : {};
  }
  if (path.startsWith("/guide/lessons")) {
    return guideLessons.map(({ body_md, ...rest }) => ({ ...rest, completed: mockGuideProgress.has(rest.id) }));
  }
  if (path.startsWith("/guide/progress")) {
    const total = guideLessons.length;
    const completed = mockGuideProgress.size;
    const sorted = [...guideLessons].sort((a, b) => a.level - b.level || a.order_in_level - b.order_in_level);
    const next = sorted.find((l) => !mockGuideProgress.has(l.id));
    return {
      completed, total, percent: total ? Math.round((completed / total) * 100) : 0,
      next_lesson: next ? { slug: next.slug, level: next.level, title: next.title } : null,
    };
  }
  if (path.startsWith("/calc/tokens")) {
    const body = JSON.parse(options.body || "{}");
    const tokens = Math.round((body.text || "").length / 3.2);
    const contextWindow = body.model === "claude-haiku-4-5" ? 200_000 : 1_000_000;
    // В моке EN стабильно ~35% дешевле по токенам — имитирует эффект кириллицы для превью,
    // реальный расчёт — через argostranslate на бэкенде (см. app/services/translate.py).
    const enTokens = Math.round(tokens / 1.35);
    const priceStandard = +(tokens / 1_000_000 * 3).toFixed(6);
    return {
      tokens,
      approx: true,
      tokenizer_note: "Оценка через tiktoken — не официальный токенайзер Claude.",
      cost_estimate_usd: priceStandard,
      price_standard: priceStandard,
      price_with_caching: +(priceStandard * 0.1).toFixed(6),
      price_with_batch: +(priceStandard * 0.5).toFixed(6),
      model_tokenizer_note: null,
      context_window: contextWindow,
      ru_context_pct: +(tokens / contextWindow * 100).toFixed(2),
      en_tokens: tokens > 0 ? enTokens : null,
      en_context_pct: tokens > 0 ? +(enTokens / contextWindow * 100).toFixed(2) : null,
      ru_vs_en_delta_pct: tokens > 0 ? Math.round((tokens - enTokens) / enTokens * 100) : null,
    };
  }
  if (path === "/events" && options.method === "POST") return { logged: JSON.parse(options.body || "{}").events?.length || 0 };
  if (path === "/admin/stats") {
    return {
      total_users: 842,
      subscribed_users: 611,
      dau: 96,
      wau: 340,
      mau: 612,
      feature_usage: [
        { event: "view_entry", count: 1204 },
        { event: "view_tool", count: 843 },
        { event: "search", count: 412 },
        { event: "view_component", count: 201 },
      ],
      sources: [
        { source: "organic", count: 401 },
        { source: "vcru", count: 220 },
        { source: "ads1", count: 132 },
        { source: "friend_share", count: 89 },
      ],
    };
  }
  if (path === "/admin/analytics") {
    const days = Array.from({ length: 14 }).map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (13 - i));
      return {
        day: d.toISOString().slice(0, 10),
        active: 40 + Math.round(Math.sin(i / 2) * 20 + i * 2),
        new_users: 4 + Math.round(Math.cos(i / 3) * 3 + 1),
      };
    });
    return {
      activity_trend: days,
      top_entries: [
        { slug: "cc-slash-commands", title: "Слэш-команды Claude Code", section: "code", views: 312 },
        { slug: "con-cyrillic-tokenization", title: "Токенизация кириллицы", section: "theory", views: 244 },
        { slug: "cc-claude-md-config", title: "CLAUDE.md: конфигурация проекта", section: "code", views: 198 },
      ],
      top_tools: [
        { repo: "anthropics/claude-code", name: "claude-code", category: "apps/desktop", views: 271 },
        { repo: "some/mcp-server", name: "mcp-server-fs", category: "mcp/servers", views: 118 },
      ],
      top_searches: [
        { query: "mcp", count: 61 },
        { query: "hooks", count: 44 },
        { query: "claude.md", count: 39 },
        { query: "subagent", count: 22 },
      ],
      section_interest: [
        { section: "code", views: 640 },
        { section: "theory", views: 280 },
        { section: "chat", views: 190 },
        { section: "design", views: 94 },
      ],
      top_prompts: prompts.map((p) => ({ slug: p.slug, title: p.title, category: p.category, copies_count: p.copies_count })),
      top_liked: [{ slug: "cc-slash-commands", title: "Слэш-команды Claude Code", likes: 12, dislikes: 1 }],
      top_disliked: [{ slug: "con-cyrillic-tokenization", title: "Токенизация кириллицы", likes: 2, dislikes: 5 }],
      top_favorites: [
        { item_type: "entry", ref: "cc-slash-commands", title: "Слэш-команды Claude Code", count: 18 },
        { item_type: "tool", ref: "anthropics/claude-code", title: "claude-code", count: 14 },
      ],
    };
  }
  if (path === "/admin/users") {
    return [
      { tg_id: 1, username: "dev", first_seen: "2026-06-01T10:00:00Z", last_seen: "2026-07-18T09:00:00Z", is_subscribed: true },
      { tg_id: 2, username: null, first_seen: "2026-07-10T10:00:00Z", last_seen: "2026-07-17T12:00:00Z", is_subscribed: false },
    ];
  }
  if (path === "/admin/events") {
    return [
      { id: 1, tg_id: 1, event: "view_entry", payload: { slug: "cc-slash-commands", section: "code" }, created_at: "2026-07-18T09:00:00Z", username: "dev" },
      { id: 2, tg_id: 2, event: "search", payload: { q: "mcp", results: 4 }, created_at: "2026-07-17T12:00:00Z", username: null },
    ];
  }
  return {};
}
